package dev.lievit.wire;

import java.util.ArrayList;
import java.util.List;

import dev.lievit.LievitAction;
import dev.lievit.LievitComponent;
import dev.lievit.LievitProperty;
import dev.lievit.LievitRender;
import dev.lievit.Wire;

/**
 * {@code accordion}: the server-first WIRE replacement for the {@code <lv-accordion>} Lit island
 * (ADR-0012, Wave 2). A disclosure GROUP: several triggers, each expanding / collapsing its own
 * region; the open set lives here in typed Java, not in client memory, and the server re-renders
 * the template on each toggle (the client morphs the result, preserving focus + scroll). It is the
 * same disclosure idea as {@code collapsible}, composed over many items.
 *
 * <p>WHY server-state: the island held the open set in a Lit reactive {@code Set} and projected
 * each panel through a named {@code <slot>}, which is inert in light DOM, so the panel bodies
 * silently never rendered (the bug class ADR-0012 was written to kill). Here {@link #open} is a
 * {@code @Wire} list round-tripped in the signed snapshot, and the panel bodies are plain
 * server-rendered JTE owned by the template: they cannot fail to project.
 *
 * <p>Convention (blueprint 1.b): state is {@code @Wire public} fields; the toggle is a
 * {@code @LievitAction}; the disclosure a11y (WAI-ARIA APG accordion, the same Radix source the
 * island cited) lives in the template. Because a regular {@code @LievitAction} takes no forwarded
 * arguments (only the magic {@code $set}/{@code $toggle} parse inline args, runtime parity gap), the
 * clicked item is ARMED into {@link #toggleId} via {@code l:click="$set('toggleId','<id>')"} (the
 * canonical Livewire {@code wire:click="$set(...)"} idiom this repo already uses for row-arm in
 * {@code listing-list.jte}); {@link #applyToggle()} then flips that id in the open set on the
 * pre-render hook and clears the arm, so the whole interaction is one click, fully server-side, and
 * idempotent under replay (a cleared arm re-renders to a no-op). The same logic is reachable as the
 * explicit {@link #toggle()} action driven by a render-asserting IT.
 *
 * <p>The item ids + labels are server config ({@code @LievitProperty(locked = true)} so a client
 * cannot inject or rename an item); the panel bodies are OWNED template markup (the server-first
 * equivalent of children, not a {@code <slot>}). Copied in by {@code lievit add accordion}: the
 * adopter OWNS this class AND {@code accordion.jte} (rename the package, change the items, put real
 * panel markup in the owned regions).
 */
@LievitComponent(template = "lievit/accordion")
public class AccordionComponent {

    /**
     * Item ids in render order. Locked: the set of items is server config, a client cannot add,
     * remove, or rename one by editing the snapshot. Paired index-for-index with {@link #labels}.
     */
    @Wire
    @LievitProperty(locked = true)
    public List<String> itemIds = new ArrayList<>();

    /** Trigger labels, index-aligned with {@link #itemIds}. Locked alongside the ids. */
    @Wire
    @LievitProperty(locked = true)
    public List<String> labels = new ArrayList<>();

    /**
     * The currently open item ids. The single piece of disclosure state, held server-side and
     * round-tripped as a plain JSON list. For {@code single} mode it holds at most one id.
     */
    @Wire
    public List<String> open = new ArrayList<>();

    /**
     * {@code "single"} (default): at most one item open at a time; {@code "multiple"}: any number.
     * Locked: the selection mode is server policy, not a client toggle.
     */
    @Wire
    @LievitProperty(locked = true)
    public String mode = "single";

    /**
     * The item a click just armed (via the {@code $set} magic). Consumed + cleared by
     * {@link #applyToggle()} on the next render, so a click reduces to one server round-trip. Empty
     * when no toggle is pending; it never persists across a render.
     */
    @Wire
    public String toggleId = "";

    /**
     * Flips the armed {@link #toggleId} in the open set on every pre-render (the hook the dispatcher
     * runs at mount and before each re-render), then clears the arm. Empty arm = no-op, so a plain
     * re-render (or a snapshot replay carrying a cleared arm) never double-toggles: idempotent.
     */
    @LievitRender
    void applyToggle() {
        if (toggleId.isEmpty() || !itemIds.contains(toggleId)) {
            toggleId = "";
            return;
        }
        flip(toggleId);
        toggleId = "";
    }

    /**
     * Toggles the open/closed state of {@link #toggleId} (the armed item) explicitly. Same effect as
     * the {@code $set}-armed render path: provided so a caller (or a render-asserting test) can drive
     * the transition through the {@code @LievitAction} dispatch with the target supplied as a field
     * update in the same wire call (updates apply before actions, ADR-0001). Clears the arm after.
     */
    @LievitAction
    public void toggle() {
        if (!toggleId.isEmpty() && itemIds.contains(toggleId)) {
            flip(toggleId);
        }
        toggleId = "";
    }

    /** Adds the id to the open set, or removes it if already open; single mode keeps at most one. */
    private void flip(String id) {
        if (open.contains(id)) {
            open.remove(id);
            return;
        }
        if ("single".equals(mode)) {
            open.clear();
        }
        open.add(id);
    }

    /**
     * Whether an item is currently open (read by the template to render aria-expanded + the panel
     * hidden attribute).
     *
     * @param id the item id
     * @return true when the item is in the open set
     */
    public boolean isOpen(String id) {
        return open.contains(id);
    }
}

@import gg.jte.Content
@import gg.jte.output.StringOutput
@import gg.jte.html.escape.Escape
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui alert partial -- a contextual message banner whose variant drives the ARIA live-region
  role, the icon, and the colour token pair (surface + foreground + border). Static presentational:
  no enhancer, no client state.

  TIER: PARTIAL -- pure server-rendered presentation. The dismiss button (closable=true) is a real
  native <button>; the consuming template wires the action via l:click on it through `attrs`.

  STRUCTURE (scientific decision rule):
    - WAI-ARIA APG Alert pattern (https://www.w3.org/WAI/ARIA/apg/patterns/alert/): the role IS the
      entire a11y contract for a passive notification. No interactive focus management; no focus trap;
      the dismiss button is platform-native.
    - Inventory reference: Ant Design Alert (info/success/warning/error variants, icon, closable,
      description, banner mode) mapped to the lievit variant vocabulary (destructive = error).
    - Layout: shadcn new-york-v4 icon + CSS GRID composition (icon column 1, body column 2).
    - Styling: ORIGINAL generation over --lv-* tokens, look inspired by Tailwind UI (no code copied).

  A11y (WAI-ARIA alert / status):
    - role by INTENT: info/success → role="status" (polite, not urgent); warning/destructive →
      role="alert" (assertive, interrupt). Both carry implicit aria-live + aria-atomic="true" per
      the ARIA spec; the browser enforces these, so they are NOT emitted explicitly.
    - Icon (when rendered): aria-hidden="true" -- purely decorative; text conveys the meaning.
    - Dismiss button (closable=true): real <button type="button"> with aria-label="Dismiss".
      Icon-only, so the accessible name is mandatory (architecture contract §5.d).
    - title (when set): <p> element, NOT a heading. Alert banners are not document sections.
    - role="none" override: suppresses the role attribute entirely (purely decorative display).
    - The alert root is NOT focusable (tabindex is never added).

  Params:
    String  variant   = "info"    "info" | "success" | "warning" | "destructive".
    String  title     = null      optional bold heading (rendered as a <p>); when set the content
                                  is the supporting description beneath it.
    boolean icon      = true      show the variant-default icon; set false to suppress.
    String  iconName  = null      override the default variant icon with a named Lucide icon slug.
    boolean closable  = false     render the dismiss <button> (X); the consuming template wires
                                  l:click="dismiss" on it via `attrs`.
    boolean banner    = false     full-bleed layout: no border-radius, thick left-border stripe.
    String  role      = null      override the auto-derived live-region role; pass "none" to
                                  suppress the role entirely.
    String  cssClass  = ""        extra utility classes on the root.
    String  attrs     = ""        TRUSTED raw ($unsafe) -- STATIC author-typed strings only
                                  (data-testid, wire directives on the root or dismiss button).
    Map<String,String> dataAttrs = {}  SAFE escaped dynamic data-* on the root (key w/o "data-",
                                  simple identifier); each value via Escape.htmlAttribute.
    gg.jte.Content content        the primary message body.
    gg.jte.Content action = null  optional inline action slot after the body.

  Usage:
    @@template.lievit.alert(variant = "destructive", title = "Could not save",
      content = @@`The listing was not persisted.`)
    @@template.lievit.alert(variant = "success", icon = true, closable = true,
      attrs = "l:click=\"dismissAlert\"",
      content = @@`Your changes have been saved.`)
    @@template.lievit.alert(variant = "warning", banner = true,
      title = "Maintenance window",
      content = @@`The system will be unavailable from 02:00 to 04:00.`)
    @@template.lievit.alert(variant = "info", role = "none",
      content = @@`This is a decorative note already announced elsewhere.`)
--%>
@param String variant = "info"
@param String title = null
@param boolean icon = true
@param String iconName = null
@param boolean closable = false
@param boolean banner = false
@param String role = null
@param String cssClass = ""
@param String attrs = ""
@param java.util.Map<String, String> dataAttrs = java.util.Map.of()
@param gg.jte.Content content
@param gg.jte.Content action = null

<%-- Derived: effectiveRole -- role override wins; "none" suppresses the attribute. --%>
!{var _autoRole = ("warning".equals(variant) || "destructive".equals(variant)) ? "alert" : "status";}
!{var _effectiveRole = (role != null && !role.isBlank()) ? role : _autoRole;}
!{var _emitRole = !"none".equals(_effectiveRole);}

<%-- Derived: defaultIconName per variant; resolvedIconName = iconName override or default. --%>
!{var _defaultIconName = switch (variant) {
    case "success"     -> "circle-check";
    case "warning"     -> "triangle-alert";
    case "destructive" -> "circle-x";
    default            -> "info";
  };}
!{var _resolvedIconName = (iconName != null && !iconName.isBlank()) ? iconName : _defaultIconName;}

<%-- Derived: token mapping for surface bg + foreground text/icon + border/stripe.
     The EXISTING tokens have two tiers:
       --lv-color-{variant}     = the saturated intent colour (e.g. success green #16a34a)
       --lv-color-{variant}-fg  = intended foreground ON a SOLID fill of the above (= white)
     The alert uses a 10% tint of the base colour as the surface background; on that pale
     wash the solid-fill-fg (white) would be invisible. Correct approach: use the BASE
     token as both border/stripe AND as the icon/text colour against the pale tint. This is
     exactly what the existing alert.jte does and is the standard alert pattern (Tailwind UI,
     shadcn). The spec's §5 darker fg values (e.g. oklch(0.35 0.12 240)) were net-new tokens
     rejected by D4; without them, the base tone IS the fg against the tint. --%>
!{var _tone = switch (variant) {
    case "success"     -> "var(--lv-color-success)";
    case "warning"     -> "var(--lv-color-warning)";
    case "destructive" -> "var(--lv-color-destructive)";
    default            -> "var(--lv-color-info)";
  };}

<%-- Layout: grid columns depend on icon + closable.
     col 1: icon (1.25rem when icon, 0 otherwise)
     col 2: body (flex fill)
     col 3: dismiss button (var(--lv-space-6) when closable, 0 otherwise) --%>
!{var _hasIcon = icon;}
!{var _iconCol  = _hasIcon ? "1.25rem" : "0";}
!{var _dismissCol = closable ? "var(--lv-space-6)" : "0";}
!{var _gridCols = _iconCol + " 1fr " + _dismissCol;}
!{var _colGap   = (_hasIcon || closable) ? "var(--lv-space-2)" : "0";}

<%-- Banner layout: no radius, thick left stripe instead of full border. --%>
!{var _radiusStyle = banner ? "border-radius:0;" : "border-radius:var(--lv-radius-md);";}
!{var _borderStyle = banner
    ? "border:0;border-left:4px solid " + _tone + ";"
    : "border:1px solid " + _tone + ";";}

<%-- SAFE dynamic data-* attributes (mirrors button.jte exactly).
     JTE's HTML parser forbids a raw @for in attribute-NAME position, so the fragment is built
     once here -- each entry becomes data-<key>="<value>" with the VALUE escaped through JTE's
     OWN attribute escaper (Escape.htmlAttribute), then emitted with $unsafe.
     Keys must be simple identifiers ([A-Za-z][A-Za-z0-9-]*). --%>
!{var _dataAttrs_ = new StringOutput();}
!{for (var e : dataAttrs.entrySet()) {
    if (e.getKey() != null && e.getKey().matches("[A-Za-z][A-Za-z0-9-]*")) {
      _dataAttrs_.writeContent(" data-" + e.getKey() + "=\"");
      Escape.htmlAttribute(e.getValue() == null ? "" : e.getValue(), _dataAttrs_);
      _dataAttrs_.writeContent("\"");
    }
  }}
!{var _dataAttrsMarkup = _dataAttrs_.toString();}

<div
  data-slot="alert"
  data-variant="${variant}"
  role="${_emitRole ? _effectiveRole : null}"
  $unsafe{_dataAttrsMarkup}
  class="relative grid w-full items-start text-[length:var(--lv-text-sm)] leading-[var(--lv-leading)] ${cssClass}"
  style="font-family:var(--lv-font-sans);color:${_tone};background:color-mix(in srgb,${_tone} 10%,var(--lv-color-bg));${_borderStyle}${_radiusStyle}padding:var(--lv-space-3) var(--lv-space-4);grid-template-columns:${_gridCols};column-gap:${_colGap};row-gap:var(--lv-space-1);"
  $unsafe{attrs}
>
  @if(_hasIcon)
    <span
      aria-hidden="true"
      style="grid-column:1;grid-row:1;display:inline-flex;align-items:center;color:${_tone};"
    >@template.lievit.icon(name = _resolvedIconName, size = "1rem")</span>
  @endif
  <div data-slot="alert-body" style="grid-column:2;grid-row:1;display:flex;flex-direction:column;gap:var(--lv-space-1);">
    @if(title != null && !title.isBlank())
      <p data-slot="alert-title" style="margin:0;font-size:var(--lv-text-sm);font-weight:var(--lv-font-medium);letter-spacing:-0.01em;line-height:var(--lv-leading);">${title}</p>
    @endif
    <div data-slot="alert-content" style="font-size:var(--lv-text-sm);line-height:var(--lv-leading);">${content}</div>
    @if(action != null)
      <div data-slot="alert-action" style="margin-top:var(--lv-space-1);display:flex;align-items:center;gap:var(--lv-space-2);">${action}</div>
    @endif
  </div>
  @if(closable)
    <button
      type="button"
      aria-label="Dismiss"
      data-slot="alert-dismiss"
      style="grid-column:3;grid-row:1;align-self:start;display:inline-flex;align-items:center;justify-content:center;width:var(--lv-space-6);height:var(--lv-space-6);border:0;background:transparent;cursor:pointer;border-radius:var(--lv-radius-sm);color:var(--lv-color-fg);flex-shrink:0;outline:none;transition:box-shadow var(--lv-duration-fast) var(--lv-ease);"
      class="focus-visible:shadow-[var(--lv-ring)]"
    >@template.lievit.icon(name = "x", size = "1rem")</button>
  @endif
</div>

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 *
 * alert-dialog.css -- component-scoped styles for the alert-dialog partial.
 *
 * Scope: [data-slot="alert-dialog-confirm"] hover tint per data-variant.
 * The confirm button background is set inline via style= (token var reference, server-driven),
 * so hover must be driven via a CSS rule rather than Tailwind utility hover: variants
 * (which would conflict with the inline style specificity). These rules use color-mix to
 * produce a 90% tint of the intent token, matching the button.jte hover pattern.
 *
 * No inline on*= handlers, no inline <script>: CSP-clean by construction.
 */

[data-slot="alert-dialog-confirm"][data-variant="destructive"]:hover:not(:disabled) {
  background: color-mix(in srgb, var(--lv-color-destructive) 90%, transparent) !important;
}

[data-slot="alert-dialog-confirm"][data-variant="warning"]:hover:not(:disabled) {
  background: color-mix(in srgb, var(--lv-color-warning) 90%, transparent) !important;
}

[data-slot="alert-dialog-confirm"][data-variant="default"]:hover:not(:disabled),
[data-slot="alert-dialog-confirm"]:not([data-variant="destructive"]):not([data-variant="warning"]):hover:not(:disabled) {
  background: color-mix(in srgb, var(--lv-color-primary) 90%, transparent) !important;
}

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 */
package dev.lievit.wire;

import dev.lievit.LievitAction;
import dev.lievit.LievitComponent;
import dev.lievit.LievitProperty;
import dev.lievit.Wire;

/**
 * {@code alert-dialog}: the server-first WIRE confirm-modal, the {@code role="alertdialog"}
 * specialization of the dialog wire (ADR-0012, Wave 3). It is the interruptive prompt that demands
 * a response (delete this? discard changes?): a title, a description, a destructive-or-primary
 * confirm button and a cancel button, whose open-state lives here in typed Java, not in client
 * memory. The server re-renders the template on {@link #open()} / {@link #confirm()} /
 * {@link #cancel()} and the client morphs the result.
 *
 * <p>WHY a separate component and not the plain {@link DialogComponent}: WAI-ARIA distinguishes
 * {@code role="dialog"} (general) from {@code role="alertdialog"} (an interruptive prompt requiring
 * a response). A confirm is the alertdialog case, so the template sets {@code role="alertdialog"}
 * and the footer is NOT an owned free-form region but two real, named buttons (the destructive
 * action + cancel) wired with {@code l:click}. It builds ON the dialog wire's model (the same
 * server-held open-state + the owned-body finding from Wave 2), specialized for the confirm shape.
 *
 * <p>WHY it composes the dialog wire's STRUCTURE rather than the dialog COMPONENT: a wire template
 * is rendered with ONLY its own {@code @Wire} fields + {@code _component} (JteTemplateAdapter, the
 * Wave 0 finding), so one wire component cannot render another wire component as a nested live
 * instance with a fresh snapshot. The server-first equivalent of "compose the dialog" is therefore
 * to render the dialog's overlay/panel STRUCTURE (the {@code role}, the {@code aria-modal}, the
 * {@code hidden}-when-closed overlay, the title/description header) inside this component's own
 * owned template, specialized to {@code role="alertdialog"} with the confirm footer. The result is
 * a single self-contained wire component with no {@code <lv-dialog>} reference anywhere.
 *
 * <p>Convention (blueprint 1.b): state is {@code @Wire public} fields; the actions are
 * {@code @LievitAction} methods; the modal a11y (WAI-ARIA APG alertdialog: {@code role=alertdialog},
 * {@code aria-modal}, {@code aria-labelledby} -> the title, {@code aria-describedby} -> the
 * description) lives in the template. {@code title} + {@code description} + the button labels +
 * {@code open} round-trip; {@code destructive} is locked so a client cannot downgrade a
 * server-mandated destructive confirm to a benign one (or vice-versa) by editing the snapshot.
 *
 * <p>WHAT happens on confirm is the adopter's: {@link #confirmed} is a wire flag the host page reads
 * after the round-trip (or the adopter overrides {@link #confirm()} to run the destructive operation
 * server-side, with authz, before closing). Either way the server stays the single owner of the
 * outcome; the client only fires the action.
 *
 * <p>Copied in by {@code lievit add alert-dialog}: the adopter OWNS this class (rename it, move the
 * package, do the real work in {@link #confirm()} with server-side authz) AND the
 * {@code alert-dialog.jte} template.
 */
@LievitComponent(template = "lievit/alert-dialog")
public class AlertDialogComponent {

    /** Open state: the single piece of modal state, held server-side. */
    @Wire
    public boolean open = false;

    /** The prompt headline; wired to {@code aria-labelledby}. Round-trips. */
    @Wire
    public String title = "Are you sure?";

    /** The supporting explanation; wired to {@code aria-describedby}. Empty omits it. Round-trips. */
    @Wire
    public String description = "";

    /** The confirm button label. Round-trips. */
    @Wire
    public String actionLabel = "Confirm";

    /** The cancel button label. Round-trips. */
    @Wire
    public String cancelLabel = "Cancel";

    /**
     * When true the confirm button is the destructive (red) affordance + the title carries a
     * triangle-alert icon. Locked so a client cannot flip a server-mandated destructive confirm to a
     * benign one (or vice-versa) by editing the snapshot payload.
     */
    @Wire
    @LievitProperty(locked = true)
    public boolean destructive = false;

    /**
     * Set true once {@link #confirm()} has run, false again on {@link #cancel()} / {@link #open()}.
     * The host page reads this after the round-trip to learn the outcome; an adopter that does the
     * destructive work directly in {@link #confirm()} can ignore it.
     */
    @Wire
    public boolean confirmed = false;

    /** Opens the prompt, clearing any prior outcome so a re-open starts unanswered. */
    @LievitAction
    public void open() {
        confirmed = false;
        open = true;
    }

    /**
     * Confirms the prompt: records the outcome and closes. The adopter overrides this to run the
     * destructive operation server-side (with authz) before it closes; doing it here keeps the
     * server the single owner of the outcome.
     */
    @LievitAction
    public void confirm() {
        confirmed = true;
        open = false;
    }

    /** Cancels the prompt: clears the outcome and closes. */
    @LievitAction
    public void cancel() {
        confirmed = false;
        open = false;
    }
}

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 */

/**
 * overlay enhancer (ADR-0012, server-first): the ONE CSP-clean typed-TS module that gives the whole
 * server-first modal-overlay family -- `dialog`, `sheet`, `drawer`, `alert-dialog` -- the three
 * client behaviours a modal owes by WAI-ARIA APG that the server cannot do (they are pure
 * focus-mechanics, not state): focus-trap, Escape-to-close, and return-focus.
 *
 * The open/closed STATE stays server-owned (the wire `@Wire boolean open`): the overlay root carries
 * the boolean `hidden` attribute, the server flips it on `open`/`close`, the client morphs it. This
 * module never decides open-state and never round-trips the wire to set it. It only:
 *
 *   - **traps Tab** inside `[data-lv-<kind>-panel]` while the overlay is shown (Tab past the last
 *     focusable wraps to the first, Shift+Tab past the first wraps to the last), so keyboard focus
 *     cannot leak to the page behind the modal (APG "Keyboard Interaction" for a modal dialog);
 *   - **routes Escape to the server close path** by clicking the overlay's own dismiss button -- the
 *     real `l:click="close"` / `l:click="cancel"` button the template already renders. Escape thus
 *     takes the SAME path as the button: the runtime's `l:click` directive fires the wire action and
 *     the server re-renders `hidden`. This keeps the enhancer fully decoupled from the wire codec
 *     (it touches no snapshot, no dispatcher) and CSP-clean (it attaches listeners in code; the
 *     strict CSP refuses inline `on*=` handlers). A non-dismissible dialog (no dismiss button)
 *     simply has no Escape target, matching the locked server `dismissible=false`;
 *   - **moves focus in on open and restores it on close**, observing the `hidden` attribute via a
 *     MutationObserver (the server is the only writer of `hidden`, so observing it is how the client
 *     learns the state changed). On open it remembers `document.activeElement` (the trigger) and
 *     focuses the panel's initial element; on close it returns focus to that remembered opener.
 *
 * Initial-focus rule (APG): focus the element marked `[data-lv-autofocus]` if present, else the
 * first focusable in the panel. An alert-dialog is interruptive, so its template marks the CANCEL
 * button `[data-lv-autofocus]` (focus-on-cancel default, the safe choice for a destructive prompt);
 * a plain dialog focuses its first focusable, falling back to the panel itself (`tabindex=-1`).
 *
 * Idempotent: call {@link enhanceOverlay} once per root (it marks each root) and again after a DOM
 * swap; already-enhanced roots are skipped. {@link enhanceAllOverlays} wires every overlay on the
 * page. One module, the whole family: dialog/sheet/drawer/alert-dialog all share these mechanics.
 */

/** The four server-first modal overlays this module enhances (their root data-* hooks). */
const OVERLAY_KINDS = ["dialog", "sheet", "drawer", "alert-dialog"] as const;
type OverlayKind = (typeof OVERLAY_KINDS)[number];

const ENHANCED = "data-lv-overlay-enhanced";
const RETURN_FOCUS = "_lvOverlayReturnFocus";

/** The CSS selector that matches every modal-overlay root (the union of the four kinds). */
const ROOT_SELECTOR = OVERLAY_KINDS.map((k) => `[data-lv-${k}]`).join(",");

/** Elements that can hold keyboard focus inside a panel (the standard focus-trap set). */
const FOCUSABLE =
  'a[href],area[href],button:not([disabled]),input:not([disabled]),select:not([disabled]),' +
  'textarea:not([disabled]),[tabindex]:not([tabindex="-1"]),[contenteditable="true"]';

/** A root augmented with the opener it must return focus to on close. */
type OverlayRoot = HTMLElement & { [RETURN_FOCUS]?: Element | null };

/** The overlay kind of a root (which `data-lv-<kind>` it carries), or null if it is not an overlay. */
function kindOf(root: HTMLElement): OverlayKind | null {
  return OVERLAY_KINDS.find((k) => root.hasAttribute(`data-lv-${k}`)) ?? null;
}

/** The role=dialog|alertdialog panel of an overlay root. */
function panelOf(root: HTMLElement, kind: OverlayKind): HTMLElement | null {
  return root.querySelector<HTMLElement>(`[data-lv-${kind}-panel]`);
}

/**
 * The button whose click runs the server close/cancel path. Prefer an explicit dismiss button
 * (`-close` for dialog/sheet/drawer); an alert-dialog has no `-close`, its Escape routes to
 * `-cancel`. Returns null for a non-dismissible dialog (no dismiss affordance is rendered).
 */
function dismissButtonOf(root: HTMLElement, kind: OverlayKind): HTMLButtonElement | null {
  return (
    root.querySelector<HTMLButtonElement>(`[data-lv-${kind}-close]`) ??
    root.querySelector<HTMLButtonElement>(`[data-lv-${kind}-cancel]`)
  );
}

/** True when the overlay is shown (the server did not set the boolean `hidden`). */
function isOpen(root: HTMLElement): boolean {
  return !root.hasAttribute("hidden");
}

/** The visible, focusable elements inside a panel, in DOM order. */
function focusablesIn(panel: HTMLElement): HTMLElement[] {
  return Array.from(panel.querySelectorAll<HTMLElement>(FOCUSABLE)).filter(
    (el) => el.offsetParent !== null || el === document.activeElement
  );
}

/** Move focus to the panel's initial element (its `[data-lv-autofocus]`, else first focusable, else the panel). */
function focusInitial(panel: HTMLElement): void {
  const marked = panel.querySelector<HTMLElement>("[data-lv-autofocus]");
  const target = marked ?? focusablesIn(panel)[0];
  if (target) {
    target.focus();
    return;
  }
  // No focusable child: make the panel itself focusable and focus it (APG fallback).
  if (!panel.hasAttribute("tabindex")) {
    panel.setAttribute("tabindex", "-1");
  }
  panel.focus();
}

/** Return focus to the element that had it when the overlay opened (the trigger). */
function restoreFocus(root: OverlayRoot): void {
  const opener = root[RETURN_FOCUS];
  if (opener instanceof HTMLElement && opener.isConnected) {
    opener.focus();
  }
  root[RETURN_FOCUS] = null;
}

/** Keep Tab within the panel: wrap from last->first (Tab) and first->last (Shift+Tab). */
function trapTab(event: KeyboardEvent, panel: HTMLElement): void {
  const focusables = focusablesIn(panel);
  if (focusables.length === 0) {
    // Nothing focusable: keep focus on the panel, never leak to the page behind.
    event.preventDefault();
    panel.focus();
    return;
  }
  const first = focusables[0];
  const last = focusables[focusables.length - 1];
  const active = document.activeElement;
  if (event.shiftKey && (active === first || !panel.contains(active))) {
    event.preventDefault();
    last.focus();
  } else if (!event.shiftKey && active === last) {
    event.preventDefault();
    first.focus();
  }
}

/**
 * Enhance one overlay root: trap Tab + route Escape to the server close path + drive focus on the
 * open<->close transition. No-op if it is already enhanced or not a modal overlay root.
 *
 * @param root a `[data-lv-dialog|sheet|drawer|alert-dialog]` overlay root
 */
export function enhanceOverlay(root: HTMLElement): void {
  if (root.hasAttribute(ENHANCED)) {
    return;
  }
  const kind = kindOf(root);
  if (kind === null) {
    return;
  }
  root.setAttribute(ENHANCED, "");

  const panel = panelOf(root, kind);
  if (panel === null) {
    return;
  }

  // Tab-trap + Escape: a single keydown listener on the root (the panel lives inside it).
  root.addEventListener("keydown", (event: KeyboardEvent) => {
    if (!isOpen(root)) {
      return;
    }
    if (event.key === "Tab") {
      trapTab(event, panel);
      return;
    }
    if (event.key === "Escape") {
      const dismiss = dismissButtonOf(root, kind);
      if (dismiss) {
        // Route Escape through the SAME server path as the button (its l:click action).
        event.preventDefault();
        dismiss.click();
      }
    }
  });

  // Focus management across the server-owned open<->close transition: the server writes `hidden`,
  // we observe it. On open: remember the opener + focus the initial element. On close: restore.
  const holder = root as OverlayRoot;
  const observer = new MutationObserver(() => {
    if (isOpen(root)) {
      if (!holder[RETURN_FOCUS]) {
        holder[RETURN_FOCUS] = document.activeElement;
      }
      focusInitial(panel);
    } else if (holder[RETURN_FOCUS]) {
      restoreFocus(holder);
    }
  });
  observer.observe(root, { attributes: true, attributeFilter: ["hidden"] });

  // If the root mounted already-open (SSR open=true), focus it now without waiting for a mutation.
  if (isOpen(root)) {
    holder[RETURN_FOCUS] = document.activeElement;
    focusInitial(panel);
  }
}

/** Enhance every modal overlay on the page (call on load + after DOM swaps). Idempotent. */
export function enhanceAllOverlays(scope: ParentNode = document): void {
  scope
    .querySelectorAll<HTMLElement>(ROOT_SELECTOR)
    .forEach((root) => enhanceOverlay(root));
}

@import gg.jte.output.StringOutput
@import gg.jte.html.escape.Escape
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui avatar partial -- a circular (or square) frame displaying a person or entity:
  image, initials fallback, or icon fallback. Static display, zero client state, CSP-clean.

  TIER: STATIC presentational -> JTE partial. Server already holds `src`, `name`, and the
  fallback data, so the right branch is emitted server-side with no JS. The strict
  `script-src 'self'` CSP refuses inline `on*=` handlers; the anti-pattern that caused the
  silent-slot bug (an onerror attribute that never fired in prod) is a non-starter here.
  If the adopter needs a broken-image swap, they wire it from their own TS module against
  `data-slot="avatar"` -- the partial stays inert.

  STRUCTURE (scientific decision rule):
  Ant Design Avatar (the inventory reference) splits Image / Initials / Icon into three
  paths selected by priority. Server-side the priority is computed once in `!{var ...}`
  locals and the correct branch is emitted directly; no JS load-state machine is needed.
  shadcn/Radix split Root+Image+Fallback to hide the fallback after the image loads -- a
  pure-JS concern we resolve server-side. Tailwind UI provides the visual tone reference
  (ORIGINAL markup over --lv-* tokens, no code copied). APG Button pattern covers the
  interactive wrappers (href -> <a>, clickable -> <button>).

  SIZE (diameter-based, not height-based -- architecture-contract §5.b D5). Avatar is a
  square/circle, not a bar control, so its natural sizing axis is its diameter. The scale
  is NOT toolbar-pixel-aligned and deliberately extends beyond the sm|md|lg three-step:
    xs  -> diameter var(--lv-space-6)  (1.5rem,  24px)  font --lv-text-2xs
    sm  -> diameter var(--lv-space-8)  (2rem,    32px)  font --lv-text-xs
    md  -> diameter var(--lv-space-10) (2.5rem,  40px)  font --lv-text-sm  [default]
    lg  -> diameter var(--lv-space-12) (3rem,    48px)  font --lv-text-base
    xl  -> diameter var(--lv-space-16) (4rem,    64px)  font --lv-text-lg
    2xl -> diameter var(--lv-space-20) (5rem,    80px)  font --lv-text-xl
  `data-size` is stamped on the root for CSS hooks and acceptance tests.

  SHAPE: circle (--lv-radius-full, default) | square (--lv-radius-md).
  `data-shape` is stamped on the root.

  COLOR (background for initials / icon fallback):
  - explicit `color` param: one of the shared intent slugs mapped to --lv-color-<intent> /
    --lv-color-<intent>-fg via a switch.
  - null (auto): a stable intent is derived by hashing `name` (or `initials`) with a simple
    deterministic modulo over the 6-intent set so the same string always yields the same hue.
    Hash runs server-side; no JS involved.
  - no name AND no initials AND fallback reaches icon: defaults to `default` (muted).
  `data-variant` carries the resolved intent slug for test hooks.

  STATUS DOT: an absolutely-positioned `<span aria-hidden="true">` at the bottom-right corner,
  coloured by intent token. Status `xs` is suppressed (too small to read). The dot is aria-hidden
  because the surrounding context (a list row, adjacent label) conveys the presence meaning.

  INTERACTIVE WRAPPERS (href / clickable):
  - href set -> root element is <a href> (APG link, native focus + Tab + Enter).
  - clickable=true (no href) -> root element is <button type="button"> (APG button, native
    focus + Tab + Enter + Space). The inner frame span inside the wrapper carries
    aria-hidden="true" so the wrapper's aria-label is not double-announced.
  - Neither -> root is <span>, not in tab order, no role.

  FALLBACK PRECEDENCE (server-evaluated in !{var ...} locals; never forks on client state):
  1. src present and non-blank         -> <img> with resolved alt.
  2. initials or name (auto-derive)    -> initials text in intent background.
  3. icon slug present (default "user") -> @template.lievit.icon in intent background.
  4. all absent (icon=null)            -> bare frame, --lv-color-muted-bg background, no content.

  A11y (no dedicated WAI-ARIA APG pattern for a standalone display avatar; platform rules apply):
  - <img> path: `alt` from `alt` param else `name` else `""` (decorative). If `ariaHidden=true`,
    alt is forced to `""`.
  - initials / icon path (no <img>): root <span> carries `aria-label="${name}"` (when name is
    present and ariaHidden=false), so screen readers announce the person without an image.
  - ariaHidden=true: stamps aria-hidden="true" on the root and suppresses aria-label; <img> gets
    alt="" (the whole avatar is decorative in that context -- adjacent text identifies the person).
  - <a href> wrapper: accessible name = hrefLabel if set, else the bubbled-up <img alt> / inner
    aria-label. Inner frame spans aria-hidden="true" to avoid double-announcement.
  - <button> wrapper: accessible name = ariaLabel if set, else `name`. Inner frame aria-hidden.
    When neither ariaLabel nor name is available and clickable=true, a dev-visible comment is
    emitted (the button would be inaccessible) and no <button> is rendered.
  - status dot <span>: always aria-hidden="true" (presence meaning comes from surrounding context).
  - Focus ring: entirely platform-managed via :focus-visible on the <a>/<button> wrapper and the
    --lv-ring token -- no JS, no special avatar logic.

  ESCAPING CHANNELS (same rule as button.jte):
  - attrs (TRUSTED, $unsafe): static author-typed strings only (e.g. data-testid="...").
    NEVER fed DB-derived values.
  - dataAttrs (SAFE, escaped): Map<String,String> of dynamic data-* attributes; each value
    is escaped through Escape.htmlAttribute (same routine as button.jte). Use for per-row
    wire args when the avatar appears in a reactive list. Keys: simple identifiers without
    the leading "data-" prefix.

  WIRE ACTION: avatars in reactive lists that need per-row wire actions use the wrapping
  wire template's l:click + wireArgs pattern; the avatar partial stays action-free (see
  button.jte wireClick/wireArgs for the full pattern -- compose as needed).

  TOKEN READS: --lv-space-6/8/10/12/16/20 (diameters), --lv-space-2/3/4 (avatar-group overlap),
  --lv-radius-full (circle), --lv-radius-md (square), --lv-color-<intent>/<intent>-fg (six intent
  pairs + muted for bare), --lv-color-muted-bg (bare background), --lv-color-border (1px ring),
  --lv-color-bg (group gap fill), --lv-ring (focus-visible), --lv-text-2xs/xs/sm/base/lg/xl
  (initials size per tier), --lv-font-sans (typeface), --lv-font-medium (initials weight),
  --lv-z-base (status dot stacking). ADDITIVE tokens added: --lv-space-20, --lv-text-2xs.

  AVATAR-GROUP (micro-partial `avatar-group.jte`): see registry/jte/avatar-group.jte.

  Params:
    String  src         = null      image URL; null/blank -> falls back to initials or icon.
    String  name        = null      full display name: used to derive initials (first letters
                                    of first two whitespace-separated words, uppercased) AND as
                                    aria-label / img alt when alt is not explicit.
    String  alt         = null      explicit img alt. null -> use name. "" -> decorative.
    String  initials    = null      override auto-derived initials (takes precedence over name).
    String  icon        = "user"    Lucide icon slug rendered when src and initials are absent.
                                    null -> suppress icon; renders the bare background only.
    String  size        = "md"      xs | sm | md | lg | xl | 2xl (diameter-based, see SIZE above).
    String  shape       = "circle"  circle | square.
    String  color       = null      intent slug: default | primary | secondary | success |
                                    warning | destructive | accent. null -> auto-hash from name.
    String  status      = null      online | away | busy | offline; null -> no dot. xs suppressed.
    String  href        = null      makes the avatar a navigation link (<a href>).
    String  hrefLabel   = null      aria-label for the <a> wrapper.
    boolean clickable   = false     true -> wraps in <button type="button">.
    String  ariaLabel   = null      aria-label for the <button> wrapper (falls back to name).
    boolean ariaHidden  = false     stamps aria-hidden="true" on the root; suppresses aria-label.
    String  cssClass    = ""        extra utility classes on the root element.
    String  attrs       = ""        TRUSTED raw attribute string ($unsafe) -- STATIC strings only.
    java.util.Map<String,String> dataAttrs = java.util.Map.of()
                                    SAFE dynamic data-* (key without "data-", simple identifier;
                                    each value escaped via Escape.htmlAttribute).

  Usage:
    @template.lievit.avatar(name = "Francesco Bilotta", src = user.avatarUrl())
    @template.lievit.avatar(name = "Luca Cecchetto", size = "lg")
    @template.lievit.avatar(initials = "FB", color = "primary", size = "sm")
    @template.lievit.avatar(name = "Bot", icon = "bot", size = "xl")
    @template.lievit.avatar(name = "Ada", src = url, status = "online")
    @template.lievit.avatar(name = "Ada", href = "/users/1", hrefLabel = "View Ada's profile")
    @template.lievit.avatar(name = "Ada", clickable = true, ariaLabel = "Select Ada")
    @template.lievit.avatar(name = "Ada", ariaHidden = true)   (decorative, adjacent label exists)
--%>
@param String src = null
@param String name = null
@param String alt = null
@param String initials = null
@param String icon = "user"
@param String size = "md"
@param String shape = "circle"
@param String color = null
@param String status = null
@param String href = null
@param String hrefLabel = null
@param boolean clickable = false
@param String ariaLabel = null
@param boolean ariaHidden = false
@param String cssClass = ""
@param String attrs = ""
@param java.util.Map<String, String> dataAttrs = java.util.Map.of()

<%-- ───────────────────────────────────────────────────────────────────────── --%>
<%-- DIAMETER + FONT-SIZE per size tier (token-based, no literal px)          --%>
<%-- ───────────────────────────────────────────────────────────────────────── --%>
!{var diamToken = switch (size) {
    case "xs"  -> "var(--lv-space-6)";
    case "sm"  -> "var(--lv-space-8)";
    case "lg"  -> "var(--lv-space-12)";
    case "xl"  -> "var(--lv-space-16)";
    case "2xl" -> "var(--lv-space-20)";
    default    -> "var(--lv-space-10)";   /* md */
  };}
!{var textSizeClass = switch (size) {
    case "xs"  -> "text-[length:var(--lv-text-2xs)]";
    case "sm"  -> "text-[length:var(--lv-text-xs)]";
    case "lg"  -> "text-[length:var(--lv-text-base)]";
    case "xl"  -> "text-[length:var(--lv-text-lg)]";
    case "2xl" -> "text-[length:var(--lv-text-xl)]";
    default    -> "text-[length:var(--lv-text-sm)]";  /* md */
  };}

<%-- STATUS DOT size (suppressed at xs -- too small to read) --%>
!{var statusDotToken = switch (size) {
    case "sm"  -> "0.5rem";
    case "lg"  -> "0.75rem";
    case "xl"  -> "0.875rem";
    case "2xl" -> "1rem";
    default    -> "0.625rem";  /* md */
  };}
!{var renderStatus = status != null && !size.equals("xs");}

<%-- ───────────────────────────────────────────────────────────────────────── --%>
<%-- SHAPE (border-radius token)                                              --%>
<%-- ───────────────────────────────────────────────────────────────────────── --%>
!{var radiusClass = "square".equals(shape)
    ? "rounded-[var(--lv-radius-md)]"
    : "rounded-[var(--lv-radius-full)]";}

<%-- ───────────────────────────────────────────────────────────────────────── --%>
<%-- FALLBACK RESOLUTION (server-side, never forks on client state)           --%>
<%-- ───────────────────────────────────────────────────────────────────────── --%>
!{var hasImage    = src != null && !src.isBlank();}
!{var resolvedInitials = (initials != null && !initials.isBlank())
    ? initials
    : (name != null && !name.isBlank()
        ? java.util.Arrays.stream(name.trim().split("\\s+"))
              .limit(2)
              .map(w -> String.valueOf(w.charAt(0)).toUpperCase())
              .collect(java.util.stream.Collectors.joining())
        : null);}
!{var hasInitials = resolvedInitials != null && !resolvedInitials.isBlank();}
!{var hasIcon     = !hasImage && !hasInitials && icon != null && !icon.isBlank();}
<%-- fallback path: 1=image  2=initials  3=icon  4=bare --%>

<%-- ───────────────────────────────────────────────────────────────────────── --%>
<%-- COLOR RESOLUTION (intent slug -> token pair)                             --%>
<%-- auto-hash: deterministic modulo over the 6-intent set from name/initials --%>
<%-- ───────────────────────────────────────────────────────────────────────── --%>
!{var intents = new String[]{"primary", "secondary", "accent", "success", "warning", "destructive"};}
!{var resolvedColor = (color != null && !color.isBlank())
    ? color
    : (!hasImage
        ? (resolvedInitials != null && !resolvedInitials.isBlank()
            ? intents[Math.abs(resolvedInitials.hashCode()) % intents.length]
            : (name != null && !name.isBlank()
                ? intents[Math.abs(name.hashCode()) % intents.length]
                : "default"))
        : "default");}
<%-- map intent slug to background + foreground CSS classes --%>
!{var colorBgClass = switch (resolvedColor) {
    case "primary"     -> "bg-[var(--lv-color-primary)] text-[var(--lv-color-primary-fg)]";
    case "secondary"   -> "bg-[var(--lv-color-secondary)] text-[var(--lv-color-secondary-fg)]";
    case "accent"      -> "bg-[var(--lv-color-accent)] text-[var(--lv-color-accent-fg)]";
    case "success"     -> "bg-[var(--lv-color-success)] text-[var(--lv-color-success-fg)]";
    case "warning"     -> "bg-[var(--lv-color-warning)] text-[var(--lv-color-warning-fg)]";
    case "destructive" -> "bg-[var(--lv-color-destructive)] text-[var(--lv-color-destructive-fg)]";
    default            -> "bg-[var(--lv-color-muted-bg)] text-[var(--lv-color-muted-fg)]";
  };}
<%-- image path uses muted background (shows while loading / if image transparent) --%>
!{var frameBgClass = hasImage ? "bg-[var(--lv-color-muted-bg)]" : colorBgClass;}

<%-- ───────────────────────────────────────────────────────────────────────── --%>
<%-- A11Y RESOLUTION                                                          --%>
<%-- ───────────────────────────────────────────────────────────────────────── --%>
!{var resolvedAlt = ariaHidden
    ? ""
    : (alt != null ? alt : (name != null ? name : ""));}
<%-- aria-label for the non-interactive frame span (initials/icon path only) --%>
!{var frameAriaLabel = (!ariaHidden && !hasImage && name != null && !name.isBlank())
    ? name : null;}
<%-- accessible name for the interactive wrappers --%>
!{var wrapperAriaLabel = ariaLabel != null ? ariaLabel : name;}
!{var isInteractive = href != null || clickable;}

<%-- SAFE dynamic data-* attributes (same pattern as button.jte) --%>
!{var dataAttrs_ = new StringOutput();}
!{for (var e : dataAttrs.entrySet()) {
    if (e.getKey() != null && e.getKey().matches("[A-Za-z][A-Za-z0-9-]*")) {
      dataAttrs_.writeContent(" data-" + e.getKey() + "=\"");
      Escape.htmlAttribute(e.getValue() == null ? "" : e.getValue(), dataAttrs_);
      dataAttrs_.writeContent("\"");
    }
  }}
!{var dataAttrsMarkup = dataAttrs_.toString();}

<%-- BASE frame classes (shared by the inner span in interactive wrappers + root in non-interactive) --%>
!{var frameBase = "relative inline-flex shrink-0 items-center justify-center overflow-hidden align-middle select-none border border-[var(--lv-color-border)] " + radiusClass + " " + frameBgClass;}

<%-- ───────────────────────────────────────────────────────────────────────── --%>
<%-- RENDER: interactive wrapper (href=<a>, clickable=<button>) or plain span --%>
<%-- ───────────────────────────────────────────────────────────────────────── --%>
@if(href != null)
  <%-- LINK WRAPPER --%>
  <a
    data-slot="avatar"
    data-size="${size}"
    data-shape="${shape}"
    data-variant="${resolvedColor}"
    href="${href}"
    aria-label="${hrefLabel}"
    aria-hidden="${ariaHidden ? "true" : null}"
    class="inline-flex ${radiusClass} outline-none focus-visible:shadow-[var(--lv-ring)] ${cssClass}"
    style="width:${diamToken};height:${diamToken};"
    $unsafe{dataAttrsMarkup}
    $unsafe{attrs}
  >
    <%-- inner frame is decorative inside the wrapper; wrapper carries the a11y name --%>
    <span class="${frameBase} w-full h-full" aria-hidden="true">
      @if(hasImage)
        <img src="${src}" alt="" loading="lazy" class="aspect-square h-full w-full object-cover">
      @elseif(hasInitials)
        <span data-slot="avatar-initials" aria-hidden="true" class="${textSizeClass} font-[var(--lv-font-medium)] leading-none">${resolvedInitials}</span>
      @elseif(hasIcon)
        @template.lievit.icon(name = icon, cssClass = "h-2/5 w-2/5")
      @endif
      @if(renderStatus)
        <span data-slot="avatar-status" data-status="${status}" aria-hidden="true"
          class="absolute bottom-0 right-0 z-[var(--lv-z-base)] rounded-[var(--lv-radius-full)] ring-2 ring-[var(--lv-color-bg)] ${switch (status) { case "online" -> "bg-[var(--lv-color-success)]"; case "away" -> "bg-[var(--lv-color-warning)]"; case "busy" -> "bg-[var(--lv-color-destructive)]"; default -> "bg-[var(--lv-color-muted)]"; }}"
          style="width:${statusDotToken};height:${statusDotToken};"
        ></span>
      @endif
    </span>
  </a>
@elseif(clickable)
  <%-- BUTTON WRAPPER: requires accessible name; emit a dev-visible warning when neither
       ariaLabel nor name is provided (the button would be inaccessible to assistive tech). --%>
  @if(wrapperAriaLabel != null && !wrapperAriaLabel.isBlank())
    <button
      type="button"
      data-slot="avatar"
      data-size="${size}"
      data-shape="${shape}"
      data-variant="${resolvedColor}"
      aria-label="${wrapperAriaLabel}"
      aria-hidden="${ariaHidden ? "true" : null}"
      class="inline-flex ${radiusClass} outline-none focus-visible:shadow-[var(--lv-ring)] cursor-pointer ${cssClass}"
      style="width:${diamToken};height:${diamToken};"
      $unsafe{dataAttrsMarkup}
      $unsafe{attrs}
    >
      <span class="${frameBase} w-full h-full" aria-hidden="true">
        @if(hasImage)
          <img src="${src}" alt="" loading="lazy" class="aspect-square h-full w-full object-cover">
        @elseif(hasInitials)
          <span data-slot="avatar-initials" aria-hidden="true" class="${textSizeClass} font-[var(--lv-font-medium)] leading-none">${resolvedInitials}</span>
        @elseif(hasIcon)
          @template.lievit.icon(name = icon, cssClass = "h-2/5 w-2/5")
        @endif
        @if(renderStatus)
          <span data-slot="avatar-status" data-status="${status}" aria-hidden="true"
