/**
 * color-picker enhancer (ADR-0012 server-first, ADR-0019 lifecycle registry).
 *
 * Mounts on every `[data-lv-color-picker]` root rendered by `lievit/color-picker.jte`.
 * Owns exactly the two irreducible client responsibilities described in the spec §1:
 *
 *   (a) CHANNEL SYNC: keeps hex input, R/G/B spinbuttons, H/S/L spinbuttons, alpha slider,
 *       and the color-preview square in sync as the user edits any one of them. Each
 *       `input` event on any channel re-derives all representations and writes the derived
 *       values. This is a pure-client derived-state calculation (sub-keystroke latency;
 *       a server round-trip per keystroke would be UX-breaking).
 *
 *   (b) POPOVER OPEN/CLOSE + FOCUS MANAGEMENT: opens the native popover API panel on
 *       trigger click, moves focus to the first visible input, records the trigger for
 *       focus-restore. Closes on Esc, focusout-outside, confirm, and cancel. Updates the
 *       trigger aria-label after confirm so AT reads the new value.
 *
 *   (c) SWATCH ROVING: swatch `role="toolbar"` already carries the `data-lievit-collection`
 *       attributes that the shared collection-nav enhancer reads at runtime. The enhancer here
 *       only handles the semantic consequences of swatch selection (apply color + live region).
 *
 *   (d) SPINBUTTON HOME/END/PAGEUP/PAGEDOWN: supplements <input type="number"> for the APG
 *       Spinbutton keys that browsers do not implement consistently.
 *
 *   (e) FORMAT TOGGLE: cycles the visible format group (hex/rgb/hsl) when the format-toggle
 *       button is clicked, updating aria-labels and hidden states.
 *
 *   (f) EYEDROPPER: checks window.EyeDropper at mount; if absent, marks the button
 *       aria-disabled + adds a title. If present, invokes it on click.
 *
 * NO framework dependency. No Alpine, no Lit. The channel math is a typed pure-function
 * module exported from this file so it is unit-testable in isolation.
 *
 * The enhancer does NOT touch any element outside its root.
 * It does NOT fire server round-trips during editing.
 * It fires exactly one external event: input + change on the native input after confirm.
 *
 * The `data-slot` selectors are stable; the enhancer is immune to markup structure changes
 * as long as the slot names in the JTE template are preserved.
 *
 * CSP-clean: no eval, no innerHTML, no dynamically-created script. All event listeners
 * are attached in code; all DOM writes use `.value`, `.setAttribute`, `.textContent`.
 *
 * Idempotent: `data-lv-cp-enhanced` is stamped on the root; re-scanning the same root
 * is a no-op.
 */

// ---------------------------------------------------------------------------
// Color math utilities (pure functions -- unit-testable in isolation)
// ---------------------------------------------------------------------------

/** Clamps a number to [min, max]. */
export function clamp(n: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, n));
}

/** Converts a 6-digit hex string (with or without leading #) to {r, g, b} (0-255 each). */
export function hexToRgb(hex: string): { r: number; g: number; b: number } | null {
  const clean = hex.startsWith("#") ? hex.slice(1) : hex;
  if (!/^[0-9a-fA-F]{6}$/.test(clean)) {
    return null;
  }
  return {
    r: parseInt(clean.slice(0, 2), 16),
    g: parseInt(clean.slice(2, 4), 16),
    b: parseInt(clean.slice(4, 6), 16),
  };
}

/** Converts {r, g, b} (0-255 each) to a lowercase 7-char hex string (#rrggbb). */
export function rgbToHex(r: number, g: number, b: number): string {
  return "#" + [r, g, b].map((c) => clamp(Math.round(c), 0, 255).toString(16).padStart(2, "0")).join("");
}

/**
 * Converts {r, g, b} (0-255 each) to {h (0-360), s (0-100), l (0-100)}.
 * Uses the standard HSL conversion algorithm.
 */
export function rgbToHsl(r: number, g: number, b: number): { h: number; s: number; l: number } {
  const fR = r / 255, fG = g / 255, fB = b / 255;
  const max = Math.max(fR, fG, fB), min = Math.min(fR, fG, fB);
  const delta = max - min;
  const l = (max + min) / 2;
  const s = delta < 1e-5 ? 0 : delta / (1 - Math.abs(2 * l - 1));
  let h = 0;
  if (delta > 1e-5) {
    if (max === fR)      h = 60 * (((fG - fB) / delta) % 6);
    else if (max === fG) h = 60 * (((fB - fR) / delta) + 2);
    else                 h = 60 * (((fR - fG) / delta) + 4);
  }
  if (h < 0) h += 360;
  return { h: clamp(Math.round(h), 0, 360), s: clamp(Math.round(s * 100), 0, 100), l: clamp(Math.round(l * 100), 0, 100) };
}

/**
 * Converts {h (0-360), s (0-100), l (0-100)} to {r, g, b} (0-255 each).
 * Standard HSL-to-RGB conversion.
 */
export function hslToRgb(h: number, s: number, l: number): { r: number; g: number; b: number } {
  const sn = s / 100, ln = l / 100;
  const c = (1 - Math.abs(2 * ln - 1)) * sn;
  const x = c * (1 - Math.abs((h / 60) % 2 - 1));
  const m = ln - c / 2;
  let r = 0, g = 0, b = 0;
  if      (h < 60)  { r = c; g = x; b = 0; }
  else if (h < 120) { r = x; g = c; b = 0; }
  else if (h < 180) { r = 0; g = c; b = x; }
  else if (h < 240) { r = 0; g = x; b = c; }
  else if (h < 300) { r = x; g = 0; b = c; }
  else              { r = c; g = 0; b = x; }
  return {
    r: clamp(Math.round((r + m) * 255), 0, 255),
    g: clamp(Math.round((g + m) * 255), 0, 255),
    b: clamp(Math.round((b + m) * 255), 0, 255),
  };
}

// ---------------------------------------------------------------------------
// Slot selectors
// ---------------------------------------------------------------------------

function slot<T extends Element = HTMLElement>(root: Element, name: string): T | null {
  return root.querySelector<T>(`[data-slot="${name}"]`);
}

function slotAll<T extends Element = HTMLElement>(root: Element, name: string): NodeListOf<T> {
  return root.querySelectorAll<T>(`[data-slot="${name}"]`);
}

// ---------------------------------------------------------------------------
// State persisted per-root
// ---------------------------------------------------------------------------

interface CpState {
  /** The last confirmed hex value (restored on cancel). */
  confirmedHex: string;
  /** The last confirmed alpha value (restored on cancel). */
  confirmedAlpha: number;
  /** Current live hex during editing (may differ from confirmedHex). */
  liveHex: string;
  /** Current format: hex | rgb | hsl. */
  format: string;
  /** Set to the slot name of the input currently being edited (for syncAll skip-self logic). */
  editingSlot: string | null;
  /** Keydown handler attached to the popover panel (for removal on cleanup). */
  popoverKeyHandler: EventListener;
  /** Focusout handler attached to the popover panel (for removal on cleanup). */
  popoverFocusoutHandler: EventListener;
}

const states = new WeakMap<Element, CpState>();

// ---------------------------------------------------------------------------
// Format group visibility management
// ---------------------------------------------------------------------------

const FORMAT_GROUPS: Record<string, string> = { hex: "hex-group", rgb: "rgb-group", hsl: "hsl-group" };

function applyFormatVisibility(root: Element, fmt: string): void {
  for (const [f, slotName] of Object.entries(FORMAT_GROUPS)) {
    const group = slot(root, slotName);
    if (group == null) continue;
    if (f === fmt) {
      group.removeAttribute("hidden");
      group.removeAttribute("aria-hidden");
    } else {
      group.setAttribute("hidden", "");
      group.setAttribute("aria-hidden", "true");
    }
  }
}

// ---------------------------------------------------------------------------
// Channel sync: write all derived representations from a source hex
// ---------------------------------------------------------------------------

function syncAll(root: Element, hex: string, alpha: number): void {
  const state = states.get(root);
  if (state == null) return;
  state.liveHex = hex;

  const rgb = hexToRgb(hex);
  if (rgb == null) return; // invalid hex; maintain last valid state

  const { r, g, b } = rgb;
  const hsl = rgbToHsl(r, g, b);

  // Skip writing back to the input that is currently being edited (to avoid overwriting
  // the user's in-progress input). We track this via state.editingSlot (set by each
  // input's own `input` event handler before calling syncAll, cleared after).
  const skip = state.editingSlot;

  // Update hex input
  const hexInput = slot<HTMLInputElement>(root, "hex-input");
  if (hexInput != null && skip !== "hex-input") hexInput.value = hex;

  // Update RGB channel inputs
  const setChannel = (slotName: string, val: number, text?: string): void => {
    const inp = slot<HTMLInputElement>(root, slotName);
    if (inp == null) return;
    if (skip !== slotName) inp.value = String(val);
    inp.setAttribute("aria-valuenow", String(val));
    if (text != null) inp.setAttribute("aria-valuetext", text);
  };

  setChannel("channel-r", r);
  setChannel("channel-g", g);
  setChannel("channel-b", b);
  setChannel("channel-h", hsl.h, `Hue: ${hsl.h} degrees`);
  setChannel("channel-s", hsl.s, `Saturation: ${hsl.s}%`);
  setChannel("channel-l", hsl.l, `Lightness: ${hsl.l}%`);

  // Update alpha aria-valuenow (value written by caller for sliders)
  const alphaInput = slot<HTMLInputElement>(root, "alpha-input");
  if (alphaInput != null) {
    if (alphaInput !== document.activeElement) alphaInput.value = String(alpha);
    alphaInput.setAttribute("aria-valuenow", String(alpha));
    alphaInput.setAttribute("aria-valuetext", `${alpha}%`);
  }

  // Update color-preview square background
  const preview = slot(root, "color-preview");
  if (preview != null) (preview as HTMLElement).style.backgroundColor = hex;

  // Update swatch aria-pressed
  for (const sw of Array.from(slotAll(root, "swatch"))) {
    const swColor = sw.getAttribute("data-color") ?? "";
    sw.setAttribute("aria-pressed", swColor.toLowerCase() === hex.toLowerCase() ? "true" : "false");
  }
}

// ---------------------------------------------------------------------------
// Derive hex from whichever channel was edited
// ---------------------------------------------------------------------------

function deriveHexFromActiveChannel(root: Element, activeSlot: string): string | null {
  const state = states.get(root);
  if (state == null) return null;

  if (activeSlot === "hex-input") {
    const inp = slot<HTMLInputElement>(root, "hex-input");
    const raw = inp?.value.trim() ?? "";
    const candidate = raw.startsWith("#") ? raw : `#${raw}`;
    return hexToRgb(candidate) != null ? candidate : null;
  }

  if (activeSlot === "channel-r" || activeSlot === "channel-g" || activeSlot === "channel-b") {
    const r = clamp(parseInt(slot<HTMLInputElement>(root, "channel-r")?.value ?? "0", 10), 0, 255);
    const g = clamp(parseInt(slot<HTMLInputElement>(root, "channel-g")?.value ?? "0", 10), 0, 255);
    const b = clamp(parseInt(slot<HTMLInputElement>(root, "channel-b")?.value ?? "0", 10), 0, 255);
    return rgbToHex(r, g, b);
  }

  if (activeSlot === "channel-h" || activeSlot === "channel-s" || activeSlot === "channel-l") {
    const h = clamp(parseInt(slot<HTMLInputElement>(root, "channel-h")?.value ?? "0", 10), 0, 360);
    const s = clamp(parseInt(slot<HTMLInputElement>(root, "channel-s")?.value ?? "0", 10), 0, 100);
    const l = clamp(parseInt(slot<HTMLInputElement>(root, "channel-l")?.value ?? "0", 10), 0, 100);
    const { r, g, b } = hslToRgb(h, s, l);
    return rgbToHex(r, g, b);
  }

  return null;
}

// ---------------------------------------------------------------------------
// Popover open / close
// ---------------------------------------------------------------------------

function openPopover(root: Element): void {
  const state = states.get(root);
  if (state == null) return;

  const panel = slot<HTMLElement>(root, "popover");
  if (panel == null) return;

  const trigger = slot<HTMLButtonElement>(root, "trigger");
  if (trigger != null) trigger.setAttribute("aria-expanded", "true");

  // Show the native popover
  if (typeof (panel as HTMLElement & { showPopover?: () => void }).showPopover === "function") {
    (panel as HTMLElement & { showPopover: () => void }).showPopover();
  } else {
    panel.removeAttribute("hidden");
    (panel as HTMLElement).style.display = "";
  }

  // Move focus to the first visible input
  const fmt = state.format;
  let firstInput: HTMLElement | null = null;
  if (fmt === "hex") {
    firstInput = slot<HTMLElement>(root, "hex-input");
  } else if (fmt === "rgb") {
    firstInput = slot<HTMLElement>(root, "channel-r");
  } else {
    firstInput = slot<HTMLElement>(root, "channel-h");
  }
  if (firstInput != null) firstInput.focus();
}

function closePopover(root: Element, restoreFocus = true): void {
  const panel = slot<HTMLElement>(root, "popover");
  if (panel == null) return;

  const trigger = slot<HTMLButtonElement>(root, "trigger");
  if (trigger != null) trigger.setAttribute("aria-expanded", "false");

  if (typeof (panel as HTMLElement & { hidePopover?: () => void }).hidePopover === "function") {
    try {
      (panel as HTMLElement & { hidePopover: () => void }).hidePopover();
    } catch {
      // hidePopover throws if the popover is already closed; ignore
    }
  } else {
    (panel as HTMLElement).style.display = "none";
  }

  if (restoreFocus && trigger != null) trigger.focus();
}

// ---------------------------------------------------------------------------
// Confirm / cancel
// ---------------------------------------------------------------------------

function confirmColor(root: Element): void {
  const state = states.get(root);
  if (state == null) return;

  const hex = state.liveHex;
  const alpha = parseInt(slot<HTMLInputElement>(root, "alpha-input")?.value ?? "100", 10);
  state.confirmedHex = hex;
  state.confirmedAlpha = isNaN(alpha) ? 100 : alpha;

  // Write to native input + fire change events (the form sees the new value)
  const native = slot<HTMLInputElement>(root, "native-input");
  if (native != null) {
    native.value = hex;
    native.dispatchEvent(new Event("input", { bubbles: true }));
    native.dispatchEvent(new Event("change", { bubbles: true }));
  }

  // Update the trigger label so AT reads the new value on next focus
  const trigger = slot<HTMLButtonElement>(root, "trigger");
  if (trigger != null) {
    trigger.setAttribute("aria-label", `Pick color: ${hex}`);
    // Also update the visible text label in the trigger
    const textSpan = trigger.querySelector<HTMLElement>("[class*='font-mono']");
    if (textSpan != null) textSpan.textContent = hex;
    // And the preview swatch
    const swatchSpan = trigger.querySelector<HTMLElement>("[aria-hidden='true']");
    if (swatchSpan != null) swatchSpan.style.backgroundColor = hex;
  }

  closePopover(root, true);
}

function cancelColor(root: Element): void {
  const state = states.get(root);
  if (state == null) return;

  // Restore all channel inputs to the last confirmed value
  syncAll(root, state.confirmedHex, state.confirmedAlpha);
  state.liveHex = state.confirmedHex;

  closePopover(root, true);
}

// ---------------------------------------------------------------------------
// Swatch application (apply color to channels WITHOUT confirming)
// ---------------------------------------------------------------------------

function applySwatchColor(root: Element, hex: string): void {
  const state = states.get(root);
  if (state == null) return;

  const alpha = parseInt(slot<HTMLInputElement>(root, "alpha-input")?.value ?? "100", 10);
  syncAll(root, hex, isNaN(alpha) ? 100 : alpha);

  // Announce via live region
  const liveRegion = slot(root, "live-region");
  if (liveRegion != null) liveRegion.textContent = `Color set to ${hex}`;
}

// ---------------------------------------------------------------------------
// Spinbutton Home / End / PageUp / PageDown (APG Spinbutton supplemental keys)
// ---------------------------------------------------------------------------

interface SpinConfig {
  min: number;
  max: number;
  largeStep: number;
  slotName: string;
}

const SPIN_CONFIGS: Record<string, SpinConfig> = {
  "channel-r": { min: 0, max: 255, largeStep: 10, slotName: "channel-r" },
  "channel-g": { min: 0, max: 255, largeStep: 10, slotName: "channel-g" },
  "channel-b": { min: 0, max: 255, largeStep: 10, slotName: "channel-b" },
  "channel-h": { min: 0, max: 360, largeStep: 10, slotName: "channel-h" },
  "channel-s": { min: 0, max: 100, largeStep: 10, slotName: "channel-s" },
  "channel-l": { min: 0, max: 100, largeStep: 10, slotName: "channel-l" },
};

function handleSpinbuttonKey(root: Element, e: KeyboardEvent, slotName: string): void {
  const cfg = SPIN_CONFIGS[slotName];
  if (cfg == null) return;

  const inp = slot<HTMLInputElement>(root, slotName);
  if (inp == null) return;

  let current = parseInt(inp.value, 10);
  if (isNaN(current)) current = 0;

  let next: number | null = null;
  if (e.key === "Home")   next = cfg.min;
  else if (e.key === "End")    next = cfg.max;
  else if (e.key === "PageUp")   next = clamp(current + cfg.largeStep, cfg.min, cfg.max);
  else if (e.key === "PageDown") next = clamp(current - cfg.largeStep, cfg.min, cfg.max);

  if (next != null) {
    e.preventDefault();
    inp.value = String(next);
    inp.setAttribute("aria-valuenow", String(next));
    inp.dispatchEvent(new Event("input", { bubbles: true }));
  }
}

// ---------------------------------------------------------------------------
// Eyedropper
// ---------------------------------------------------------------------------

function setupEyedropper(root: Element): void {
  const btn = slot<HTMLButtonElement>(root, "eyedropper-btn");
  if (btn == null) return;

  const winAny = window as unknown as Record<string, unknown>;
  const hasApi = typeof winAny["EyeDropper"] === "function";
  if (!hasApi) {
    btn.setAttribute("aria-disabled", "true");
    btn.setAttribute("title", "Not supported in this browser");
    return;
  }

  btn.addEventListener("click", () => {
    const EyeDropper = winAny["EyeDropper"] as new () => {
      open(): Promise<{ sRGBHex: string }>;
    };
    void new EyeDropper().open().then((result) => {
      const state = states.get(root);
      if (state == null) return;
      const hex = result.sRGBHex;
      const alpha = parseInt(slot<HTMLInputElement>(root, "alpha-input")?.value ?? "100", 10);
      syncAll(root, hex, isNaN(alpha) ? 100 : alpha);
    });
  });
}

// ---------------------------------------------------------------------------
// Main mount function
// ---------------------------------------------------------------------------

const ENHANCED = "data-lv-cp-enhanced";

/** Enhance one color-picker root. No-op if already enhanced. */
export function enhanceColorPicker(root: HTMLElement): void {
  if (root.hasAttribute(ENHANCED)) return;
  root.setAttribute(ENHANCED, "");

  const initialHex = (slot<HTMLInputElement>(root, "native-input")?.value ?? "#000000").toLowerCase();
  const initialFormat = root.getAttribute("data-lv-cp-format") ?? "hex";
  const alphaEnabled = root.getAttribute("data-lv-cp-alpha") === "true";

  const state: CpState = {
    confirmedHex: initialHex,
    confirmedAlpha: 100,
    liveHex: initialHex,
    format: initialFormat,
    editingSlot: null,
    popoverKeyHandler: null as unknown as EventListener,
    popoverFocusoutHandler: null as unknown as EventListener,
  };
  states.set(root, state);

  // Run initial sync to populate all channels from the server-rendered value
  syncAll(root, initialHex, 100);

  // Apply initial format visibility
  applyFormatVisibility(root, initialFormat);

  // Trigger click: open popover
  const trigger = slot<HTMLButtonElement>(root, "trigger");
  if (trigger != null) {
    trigger.addEventListener("click", () => {
      if (root.getAttribute("aria-disabled") === "true") return;
      openPopover(root);
    });
  }

  // Popover: Esc + focusout
  const panel = slot<HTMLElement>(root, "popover");
  if (panel != null) {
    const keyHandler: EventListener = (rawEvent: Event): void => {
      const e = rawEvent as KeyboardEvent;
      if (e.key === "Escape") {
        e.preventDefault();
        cancelColor(root);
      }
    };
    const focusoutHandler: EventListener = (rawEvent: Event): void => {
      const e = rawEvent as FocusEvent;
      // Close when focus leaves the popover entirely
      const related = e.relatedTarget as Node | null;
      if (related == null || !panel.contains(related)) {
        closePopover(root, true);
      }
    };
    (state as CpState).popoverKeyHandler = keyHandler;
    (state as CpState).popoverFocusoutHandler = focusoutHandler;
    panel.addEventListener("keydown", keyHandler);
    panel.addEventListener("focusout", focusoutHandler);
  }

  // Confirm / cancel buttons
  slot<HTMLButtonElement>(root, "confirm-btn")?.addEventListener("click", () => confirmColor(root));
  slot<HTMLButtonElement>(root, "cancel-btn")?.addEventListener("click", () => cancelColor(root));

  // Hex input: sync on input event
  slot<HTMLInputElement>(root, "hex-input")?.addEventListener("input", () => {
    const s = states.get(root);
    if (s != null) s.editingSlot = "hex-input";
    const hex = deriveHexFromActiveChannel(root, "hex-input");
    if (hex != null) {
      const alpha = parseInt(slot<HTMLInputElement>(root, "alpha-input")?.value ?? "100", 10);
      syncAll(root, hex, isNaN(alpha) ? 100 : alpha);
    }
    if (s != null) s.editingSlot = null;
  });

  // Channel inputs: sync on input
  const channelSlots = ["channel-r", "channel-g", "channel-b", "channel-h", "channel-s", "channel-l"];
  for (const slotName of channelSlots) {
    const inp = slot<HTMLInputElement>(root, slotName);
    inp?.addEventListener("input", () => {
      const s = states.get(root);
      if (s != null) s.editingSlot = slotName;
      // Clamp on input
      const raw = parseInt(inp.value, 10);
      const cfg = SPIN_CONFIGS[slotName];
      if (cfg != null && !isNaN(raw)) {
        const clamped = clamp(raw, cfg.min, cfg.max);
        if (clamped !== raw) inp.value = String(clamped);
      }
      const hex = deriveHexFromActiveChannel(root, slotName);
      if (hex != null) {
        const alpha = parseInt(slot<HTMLInputElement>(root, "alpha-input")?.value ?? "100", 10);
        syncAll(root, hex, isNaN(alpha) ? 100 : alpha);
      }
      if (s != null) s.editingSlot = null;
    });
    // APG Spinbutton supplemental keys
    inp?.addEventListener("keydown", (rawEvent: Event) => {
      handleSpinbuttonKey(root, rawEvent as KeyboardEvent, slotName);
    });
  }

  // Alpha input: sync aria-valuenow + aria-valuetext on input
  if (alphaEnabled) {
    slot<HTMLInputElement>(root, "alpha-input")?.addEventListener("input", (rawEvent: Event) => {
      const inp = rawEvent.target as HTMLInputElement;
      const val = clamp(parseInt(inp.value, 10), 0, 100);
      inp.setAttribute("aria-valuenow", String(val));
      inp.setAttribute("aria-valuetext", `${val}%`);
    });
  }

  // Format toggle button
  slot<HTMLButtonElement>(root, "format-toggle")?.addEventListener("click", () => {
    const s = states.get(root);
    if (s == null) return;
    const order = ["hex", "rgb", "hsl"];
    const next = order[(order.indexOf(s.format) + 1) % order.length];
    if (next == null) return;
    s.format = next;
    root.setAttribute("data-lv-cp-format", next);
    applyFormatVisibility(root, next);
    // Update format-toggle button label
    const labels: Record<string, string> = { hex: "Hex", rgb: "RGB", hsl: "HSL" };
    const btn = slot<HTMLButtonElement>(root, "format-toggle");
    if (btn != null) {
      const label = labels[next] ?? "Hex";
      btn.setAttribute("aria-label", `Format: ${label}`);
      btn.textContent = label;
    }
    // Move focus to the first input of the new format
    if (next === "hex") slot<HTMLElement>(root, "hex-input")?.focus();
    else if (next === "rgb") slot<HTMLElement>(root, "channel-r")?.focus();
    else slot<HTMLElement>(root, "channel-h")?.focus();
  });

  // Swatch buttons: apply color on click/Enter/Space (not confirm)
  for (const sw of Array.from(slotAll<HTMLButtonElement>(root, "swatch"))) {
    sw.addEventListener("click", () => {
      const color = sw.getAttribute("data-color");
      if (color != null) applySwatchColor(root, color);
    });
  }

  // Eyedropper
  setupEyedropper(root);
}

/** Enhance every `[data-lv-color-picker]` root in scope. */
export function enhanceAllColorPickers(scope: ParentNode = document): void {
  scope
    .querySelectorAll<HTMLElement>("[data-lv-color-picker]")
    .forEach((root) => enhanceColorPicker(root));
}

@import gg.jte.Content
@import gg.jte.output.StringOutput
@import gg.jte.html.escape.Escape
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui combobox partial (v-next) -- a searchable select with a progressive-enhancement
  contract (ADR-0012). JS-OFF it IS a real native <select name=...>: form-bound, platform-
  accessible, zero-JS. JS-ON the colocated combobox.enhancer.ts activates a WAI-ARIA combobox
  surface (an editable text input over a collapsible listbox) over the SAME <option> set, writing
  selections back to the native <select> so the field always POSTs under `name` regardless of JS.

  TIER: PARTIAL (+ colocated enhancer). The catalog and selected value are server-rendered HTML;
  client-side filtering + keyboard navigation are the only irreducible client bits (there is nothing
  for the server to decide between keystrokes when the catalog is already on the page).

  STRUCTURE (scientific decision rule):
  - WAI-ARIA APG Combobox with listbox popup:
    https://www.w3.org/WAI/ARIA/apg/patterns/combobox/
    Example: https://www.w3.org/WAI/ARIA/apg/patterns/combobox/examples/combobox-autocomplete-list/
    The editable <input type="text" role="combobox"> is the single tab-stop; DOM focus NEVER moves
    into the listbox (aria-activedescendant model, not roving-tabindex). This is the load-bearing
    APG distinction between a combobox and a menu/select.
  - KEYBOARD nav (ArrowUp/Down/Home/End/Enter/Escape) is delegated to the shared
    collection-nav.enhancer.ts via data-lievit-collection on the listbox. The combobox-enhancer
    intercepts keydown on the <input> and re-dispatches to the listbox for collection-nav to own;
    it also manages open/close, filter, write-back, and blur commits.
  - POPOVER SEAM: the listbox <ul> always remains in the DOM (aria-controls must resolve per APG)
    but is visually hidden when closed via the native popover + CSS; no hidden/display:none.
  - Inventory reference: Ant Design Select with search (groups, loading, clear, size, disabled).
  - Styling: ORIGINAL generation over --lv-* tokens; look inspired by Tailwind UI (no code copied).

  A11y (WAI-ARIA APG Combobox with listbox popup):
  - Input: role="combobox" aria-expanded aria-haspopup="listbox" aria-controls="<listboxId>"
    aria-autocomplete aria-activedescendant(empty) autocomplete="off" (suppresses browser dropdown).
  - Listbox: role="listbox" id="<listboxId>" aria-labelledby popover="auto" (always in DOM).
  - Options: role="option" data-lievit-item id="opt-<value>" aria-selected aria-disabled.
  - Groups: presentation wrapper + role="group" aria-labelledby on the inner <ul>.
  - Toggle button: tabindex="-1" aria-hidden="true" (visual affordance only, not a tab stop).
  - Clear button (clearable + text non-empty): tab-stop, aria-label="Clear", a real action.
  - Loading spinner: role="status" aria-label="Loading suggestions" aria-live="polite".
  - No-results: role="option" aria-disabled="true" (not a tab stop; read by AT as active item).
  - Focus stays on <input> throughout; active option is virtual (aria-activedescendant).

  Params:
    String name              the field name (POSTs JS-off; hidden input carries committed value JS-on).
    String id = name         the combobox id (for a <label for>); defaults to name.
    java.util.List<String> options = null
                             simple option list where value == label.
    java.util.Map<String, java.util.List<String>> optionGroups = null
                             group label -> option list (renders <li role="group"> in the listbox).
    gg.jte.Content content = null
                             hand-authored <option>/<optgroup> markup (wins over options/optionGroups).
    String value = null      the committed value (single selection).
    String inputText = null  the live text in the <input>; defaults to the label for value if found.
    String label = null      visible <label> text above the control.
    String ariaLabel = null  aria-label when no visible label exists.
    String placeholder = "Select..."
                             shown in the input when inputText is empty.
    String emptyText = "No results"
                             text rendered in the listbox when no options match the filter.
    boolean clearable = false
                             shows an x clear button when inputText is non-empty.
    boolean disabled = false disables the input and the toggle button.
    boolean required = false native required on the hidden form input.
    boolean invalid = false  destructive border + ring + aria-invalid="true".
    boolean loading = false  shows a spinner + aria-busy="true" on the listbox (async fetch state).
    String size = "md"       "sm" | "md" | "lg" -- height-based, toolbar-aligned.
    String mode = "select-only"
                             "free-type" (commit any typed text) | "select-only" (must pick from list).
    String autocomplete = "list"
                             "none" | "list" | "both" -- maps to aria-autocomplete.
    String cssClass = ""     extra utility classes on the wrapper root.
    String attrs = ""        TRUSTED raw ($unsafe) -- STATIC author-typed strings only.
    java.util.Map<String, String> dataAttrs = java.util.Map.of()
                             SAFE dynamic data-* attributes (value escaped via Escape.htmlAttribute).

  Usage:
    @@template.lievit.combobox(name = "agente", label = "Agente", placeholder = "Cerca agente...",
      options = java.util.List.of("Cecchetto", "Scarpino", "Meli"), value = contatto.agente()
    )
    @@template.lievit.combobox(name = "citta", optionGroups = java.util.Map.of(
      "Emilia", java.util.List.of("Parma", "Reggio"), "Lombardia", java.util.List.of("Milano")),
      label = "Citta", size = "sm"
    )
    @@template.lievit.combobox(name = "city", label = "City", mode = "free-type", clearable = true,
      options = java.util.List.of("Milan", "Rome", "Naples"), placeholder = "Type or choose...")
--%>
@param String name = null
@param String id = null
@param java.util.List<String> options = null
@param java.util.Map<String, java.util.List<String>> optionGroups = null
@param gg.jte.Content content = null
@param String value = null
@param String inputText = null
@param String label = null
@param String ariaLabel = null
@param String placeholder = "Select..."
@param String emptyText = "No results"
@param boolean clearable = false
@param boolean disabled = false
@param boolean required = false
@param boolean invalid = false
@param boolean loading = false
@param String size = "md"
@param String mode = "select-only"
@param String autocomplete = "list"
@param String cssClass = ""
@param String attrs = ""
@param java.util.Map<String, String> dataAttrs = java.util.Map.of()

!{var _id = (id != null && !id.isBlank()) ? id : name;}
!{var _inputId = _id + "-input";}
!{var _listboxId = _id + "-listbox";}
!{var _labelId = _id + "-label";}
!{var _anchorName = "--lv-combobox-" + _id;}

<%-- Resolve the displayed input text: caller-supplied inputText > matched label for value > empty. --%>
!{var _inputText = inputText != null ? inputText : (value != null && !value.isBlank() ? value : "");}
!{var _hasText = _inputText != null && !_inputText.isBlank();}

<%-- Size: height class for the input wrapper and the toggle button. COMPLETE static strings. --%>
!{var _heightClass = switch (size) {
    case "sm" -> "h-[var(--lv-space-8)]";
    case "lg" -> "h-[var(--lv-space-10)]";
    default   -> "h-[var(--lv-space-9)]";
  };}
!{var _textClass = switch (size) {
    case "sm" -> "text-[length:var(--lv-text-xs)]";
    case "lg" -> "text-[length:var(--lv-text-base)]";
    default   -> "text-[length:var(--lv-text-sm)]";
  };}

<%-- SAFE dynamic data-* attributes fragment (pattern from button.jte + badge.jte). --%>
!{var _dataAttrs_ = new StringOutput();}
!{for (var e : dataAttrs.entrySet()) {
    if (e.getKey() != null && e.getKey().matches("[A-Za-z][A-Za-z0-9-]*")) {
      _dataAttrs_.writeContent(" data-" + e.getKey() + "=\"");
      Escape.htmlAttribute(e.getValue() == null ? "" : e.getValue(), _dataAttrs_);
      _dataAttrs_.writeContent("\"");
    }
  }}
!{var _dataAttrsMarkup = _dataAttrs_.toString();}

<%-- Root wrapper. data-slot + data-size + data-mode for test selectors and styling hooks.
     data-lievit-combobox activates the colocated combobox enhancer. --%>
<div
  data-slot="combobox"
  data-size="${size}"
  data-mode="${mode}"
  data-lievit-combobox
  data-combobox-listbox-id="${_listboxId}"
  data-combobox-input-id="${_inputId}"
  data-combobox-empty-text="${emptyText}"
  data-combobox-mode="${mode}"
  data-combobox-clearable="${clearable}"
  class="relative w-full ${cssClass}"
  style="font-family:var(--lv-font-sans);"
  $unsafe{_dataAttrsMarkup}
  $unsafe{attrs}
>
  <%-- Visible label (above the control): rendered as a real <label for> so it binds to the input.
       Points to the text input (not the hidden select) so click-to-focus works with JS-on. --%>
  @if(label != null && !label.isBlank())
    <label
      id="${_labelId}"
      for="${_inputId}"
      data-slot="combobox-label"
      class="mb-[var(--lv-space-1-5)] block ${_textClass} font-[var(--lv-font-medium)] text-[var(--lv-color-fg)]"
    >${label}</label>
  @endif

  <%-- INPUT WRAPPER: the styled control row (input + optional clear + toggle button).
       The focus ring applies to the wrapper via focus-within so the ring is visible
       whether the text input or the clear button has focus. --%>
  <div
    data-slot="combobox-control"
    data-disabled="${disabled}"
    data-invalid="${invalid}"
    data-size="${size}"
    class="relative flex w-full items-center rounded-[var(--lv-radius-md)] border bg-[var(--lv-color-input)] transition-[border-color,box-shadow] outline-none data-[disabled=true]:pointer-events-none data-[disabled=true]:opacity-[var(--lv-opacity-disabled)] data-[invalid=false]:border-[var(--lv-color-border)] data-[invalid=true]:border-[var(--lv-color-destructive)] focus-within:ring-[3px] data-[invalid=false]:focus-within:ring-[color-mix(in_srgb,var(--lv-color-ring)_35%,transparent)] data-[invalid=true]:focus-within:ring-[color-mix(in_srgb,var(--lv-color-destructive)_35%,transparent)] ${_heightClass}"
  >
    <%-- THE COMBOBOX INPUT: role="combobox" per APG; aria-expanded reflects open state (closed
         server-side; JS-on opens it). aria-controls must always reference a present element. --%>
    <input
      type="text"
      id="${_inputId}"
      data-slot="combobox-input"
      role="combobox"
      aria-expanded="false"
      aria-haspopup="listbox"
      aria-controls="${_listboxId}"
      aria-autocomplete="${autocomplete}"
      aria-activedescendant=""
      aria-label="${ariaLabel}"
      aria-labelledby="${(label != null && !label.isBlank()) ? _labelId : null}"
      aria-invalid="${invalid ? "true" : null}"
      aria-required="${required ? "true" : null}"
      autocomplete="off"
      disabled="${disabled}"
      placeholder="${placeholder}"
      value="${_inputText}"
      style="anchor-name:${_anchorName};"
      class="min-w-0 flex-1 border-0 bg-transparent pl-[var(--lv-space-3)] pr-[var(--lv-space-1)] ${_textClass} text-[var(--lv-color-fg)] placeholder:text-[var(--lv-color-muted)] outline-none focus:outline-none focus-visible:outline-none disabled:pointer-events-none disabled:cursor-not-allowed"
    >

    <%-- CLEAR BUTTON: absent (not hidden) when !clearable or inputText is empty.
         Absent = zero tab-stop for an inactive action. IS in the tab sequence when rendered. --%>
    @if(clearable && _hasText)
      <button
        type="button"
        data-slot="combobox-clear"
        aria-label="Clear"
        class="flex shrink-0 items-center justify-center px-[var(--lv-space-1)] text-[var(--lv-color-muted)] hover:text-[var(--lv-color-fg)] focus-visible:outline-none focus-visible:shadow-[var(--lv-ring)] rounded-[var(--lv-radius-sm)]"
      >
        <svg aria-hidden="true" width="0.875rem" height="0.875rem" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
      </button>
    @endif

    <%-- TOGGLE BUTTON: visual affordance for pointer + touch users; NOT a tab stop per APG.
         aria-hidden: the input IS the tab-stop; AT users interact via the input. --%>
    <button
      type="button"
      data-slot="combobox-toggle"
      tabindex="-1"
      aria-hidden="true"
      aria-label="Toggle suggestions"
      disabled="${disabled}"
      class="flex shrink-0 items-center justify-center pr-[var(--lv-space-3)] pl-[var(--lv-space-1)] text-[var(--lv-color-muted)] disabled:pointer-events-none"
    >
      <svg aria-hidden="true" width="1rem" height="1rem" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"/></svg>
    </button>
  </div>

  <%-- LISTBOX PANEL: ALWAYS in the DOM so aria-controls="${_listboxId}" always resolves (APG rule).
       Visibility toggled via CSS popover seam (native popover attribute + anchor positioning), NOT
       via hidden or display:none -- the element must stay in the a11y tree as unexpanded.
       data-lievit-collection activates collection-nav.enhancer.ts in aria-activedescendant mode.
       data-lievit-collection-activedescendant-target points at the <input> (the single DOM focus
       target; collection-nav writes aria-activedescendant there). --%>
  <ul
    id="${_listboxId}"
    role="listbox"
    data-slot="combobox-listbox"
    popover="auto"
    data-lv-opener="${_inputId}"
    data-lv-wire-close="close"
    data-lievit-collection
    data-lievit-collection-orientation="vertical"
    data-lievit-collection-wrap="true"
    data-lievit-collection-activedescendant-target="#${_inputId}"
    aria-labelledby="${(label != null && !label.isBlank()) ? _labelId : null}"
    aria-busy="${loading ? "true" : "false"}"
    class="m-0 box-border w-full list-none overflow-y-auto rounded-[var(--lv-radius-lg)] border border-[var(--lv-color-border)] bg-[var(--lv-color-popover)] p-[var(--lv-space-1)] text-[var(--lv-color-popover-fg)] shadow-[var(--lv-shadow-md)] outline-none"
    style="position-anchor:${_anchorName};position-area:bottom span-right;position-try-fallbacks:flip-block;margin-block-start:var(--lv-space-1);z-index:var(--lv-z-popover);max-height:var(--lv-combobox-listbox-max-h,260px);min-width:anchor-size(width);font-family:var(--lv-font-sans);"
  >
    <%-- LOADING SPINNER: rendered before options when a server fetch is in flight.
         role="status" aria-live="polite": AT announces "Loading suggestions" politely. --%>
    @if(loading)
      <li role="status" aria-live="polite" aria-label="Loading suggestions" data-slot="combobox-loading" class="flex items-center justify-center py-[var(--lv-space-3)] text-[length:var(--lv-text-sm)] text-[var(--lv-color-muted)]">
        <span aria-hidden="true" class="inline-block h-[1rem] w-[1rem] animate-spin rounded-full border-2 border-[var(--lv-color-border)] border-t-[var(--lv-color-primary)]"></span>
      </li>
    @endif

    <%-- OPTIONS: rendered from the same option set as the native <select>.
         Each option is a data-lievit-item so collection-nav can navigate them.
         id="opt-<escaped-value>" is required for aria-activedescendant to reference the item.
         aria-selected: server-compares option value to the committed value.
         data-slot / data-combobox-option: stable hooks for the enhancer + test selectors.
         SAFE escaping: all values go through Escape.htmlAttribute for data-combobox-option
         (they are DB-derived / caller-supplied, never trusted-raw). --%>
    @if(!loading)
      @if(content != null)
        <%-- hand-authored <option>/<optgroup> content: the enhancer reads and renders these. --%>
        ${content}
      @elseif(optionGroups != null)
        !{var _grpIdx = new int[]{0};}
        @for(java.util.Map.Entry<String, java.util.List<String>> _grp : optionGroups.entrySet())
          !{var _grpId = _id + "-grp-" + _grpIdx[0]++;}
          <li role="presentation" data-slot="combobox-group-wrapper">
            <div id="${_grpId}" role="none" aria-hidden="true" data-slot="combobox-group-label" class="px-[var(--lv-space-2)] py-[var(--lv-space-1)] text-[length:var(--lv-text-xs)] font-[var(--lv-font-medium)] text-[var(--lv-color-muted)] uppercase tracking-wide select-none">${_grp.getKey()}</div>
            <ul role="group" aria-labelledby="${_grpId}" class="m-0 list-none p-0">
              @for(String _opt : _grp.getValue())
                !{var _isSelected = value != null && _opt.equals(value);}
                !{var _optId = _id + "-opt-" + _opt.replaceAll("[^A-Za-z0-9]", "-");}
                !{var _optAttr = new StringOutput();}
                !{Escape.htmlAttribute(_opt, _optAttr);}
                <li
                  role="option"
                  id="${_optId}"
                  data-lievit-item
                  data-slot="combobox-option"
                  aria-selected="${_isSelected ? "true" : "false"}"
                  data-combobox-option="$unsafe{_optAttr.toString()}"
                  class="flex cursor-pointer select-none items-center gap-[var(--lv-space-2)] rounded-[var(--lv-radius-sm)] px-[var(--lv-space-2)] py-[var(--lv-space-2)] ${_textClass} text-[var(--lv-color-popover-fg)] data-[active]:bg-[var(--lv-color-accent)] data-[active]:text-[var(--lv-color-accent-fg)] aria-selected:font-[var(--lv-font-medium)]"
                >
                  @if(_isSelected)
                    <span aria-hidden="true" class="flex h-[0.875rem] w-[0.875rem] shrink-0 items-center justify-center text-[var(--lv-color-primary)]"><svg width="0.875rem" height="0.875rem" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg></span>
                  @else
                    <span aria-hidden="true" class="h-[0.875rem] w-[0.875rem] shrink-0"></span>
                  @endif
                  ${_opt}
                </li>
              @endfor
            </ul>
          </li>
        @endfor
      @elseif(options != null)
        @for(String _opt : options)
          !{var _isSelected = value != null && _opt.equals(value);}
          !{var _optId = _id + "-opt-" + _opt.replaceAll("[^A-Za-z0-9]", "-");}
          !{var _optAttr = new StringOutput();}
          !{Escape.htmlAttribute(_opt, _optAttr);}
          <li
            role="option"
            id="${_optId}"
            data-lievit-item
            data-slot="combobox-option"
            aria-selected="${_isSelected ? "true" : "false"}"
            data-combobox-option="$unsafe{_optAttr.toString()}"
            class="flex cursor-pointer select-none items-center gap-[var(--lv-space-2)] rounded-[var(--lv-radius-sm)] px-[var(--lv-space-2)] py-[var(--lv-space-2)] ${_textClass} text-[var(--lv-color-popover-fg)] data-[active]:bg-[var(--lv-color-accent)] data-[active]:text-[var(--lv-color-accent-fg)] aria-selected:font-[var(--lv-font-medium)]"
          >
            @if(_isSelected)
              <span aria-hidden="true" class="flex h-[0.875rem] w-[0.875rem] shrink-0 items-center justify-center text-[var(--lv-color-primary)]"><svg width="0.875rem" height="0.875rem" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg></span>
            @else
              <span aria-hidden="true" class="h-[0.875rem] w-[0.875rem] shrink-0"></span>
            @endif
            ${_opt}
          </li>
        @endfor
      @else
        <%-- No options source: render the empty state immediately. --%>
        <li role="option" aria-disabled="true" data-slot="combobox-empty" class="cursor-default select-none py-[var(--lv-space-3)] px-[var(--lv-space-2)] text-center ${_textClass} text-[var(--lv-color-muted)]">${emptyText}</li>
      @endif
    @endif
  </ul>

  <%-- HIDDEN FORM INPUT: always rendered; carries the committed `value` to form POSTs.
       The visible <input type="text"> carries inputText only; this hidden input carries the
       final committed selection so the form sees the right value on submit. --%>
  <input
    type="hidden"
    name="${name}"
    value="${value}"
    data-slot="combobox-hidden"
    required="${required}"
  >

  <%-- JS-OFF NATIVE SELECT: the accessible fallback when JS has not run. The enhancer hides this
       visually (it stays in the DOM as the form-bound source for write-back) and activates the
       combobox surface above. Kept aria-hidden until the enhancer activates; the enhancer sets
       aria-hidden="true" and tabIndex=-1 on it to remove it from the AT tree. --%>
  <div data-slot="combobox-native-wrapper" class="sr-only" aria-hidden="true">
    <select
      data-combobox-native
      id="${_id}-native"
      name="${name}-native"
      disabled="${disabled}"
      required="${required}"
      tabindex="-1"
      aria-hidden="true"
    >
      @if(content != null)
        ${content}
      @elseif(optionGroups != null)
        @for(java.util.Map.Entry<String, java.util.List<String>> _ngrp : optionGroups.entrySet())
          <optgroup label="${_ngrp.getKey()}">
            @for(String _nopt : _ngrp.getValue())
              <option value="${_nopt}" selected="${value != null && _nopt.equals(value)}">${_nopt}</option>
            @endfor
          </optgroup>
        @endfor
      @elseif(options != null)
        @for(String _nopt : options)
          <option value="${_nopt}" selected="${value != null && _nopt.equals(value)}">${_nopt}</option>
        @endfor
      @endif
    </select>
  </div>
</div>

