/* When the enhancer stamps the coordinate attributes, read them via attr(). */
[data-slot="context-menu-panel"][data-menu-x] {
  --_menu-x: attr(data-menu-x type(<number>), 0);
  --_menu-y: attr(data-menu-y type(<number>), 0);
