    }

    /**
     * Opens the menu (at the {@code x}/{@code y} the enhancer set) and clears any prior selection.
     * Invoked from the {@code contextmenu} enhancer after it writes the pointer coordinates.
     */
    @LievitAction
    public void openAt() {
