    case "top-start"    -> "top span-right";
    case "top-end"      -> "top span-left";
    case "bottom-start" -> "bottom span-right";
    case "bottom-end"   -> "bottom span-left";
    case "left"         -> "left center";
    case "right"        -> "right center";
