!{var _labelFont = "sm".equals(size)
    ? "var(--lv-text-xs)"
    : "var(--lv-text-sm)";}
!{var _valueFont = switch (size) {
    case "sm" -> "var(--lv-text-sm)";
    case "lg" -> "var(--lv-text-lg)";
