package dev.lievit.wire;

import dev.lievit.LievitAction;
import dev.lievit.LievitComponent;
import dev.lievit.LievitProperty;
import dev.lievit.Wire;

/**
 * {@code popover} (WIRE variant): the server-data-driven form of the popover overlay seam
 * (ADR-0012 blueprint R4). Use this when the popover's CONTENT depends on server state and the
 * open/close decision belongs server-side: the canonical case is gest's calendar-filter popover,
 * whose panel drives a server feed (the selected filters change what the calendar queries). For a
 * popover whose content is static, use the {@code popover} JTE PARTIAL instead (native
 * {@code popover} attribute + CSS Anchor Positioning, zero JS): this wire component is the heavier
 * tier, chosen only because the content + the open-state are server-held.
 *
 * <p>WHY server-state (vs the native-popover partial): the native {@code popover} attribute owns
 * show/hide purely client-side, which is perfect when the panel body is already in the DOM. But
 * when opening the popover must FETCH or RECOMPUTE the body from server state (the filtered feed,
 * a permission-gated form), the open-state has to live server-side so the {@link #toggle()} action
 * can re-render the panel with fresh content. Here {@code open} is a {@code @Wire} boolean
 * round-tripped in the signed snapshot; the panel + its content are conditionally server-rendered
 * ({@code @if(open)} in the template), so the body CANNOT fail to project (the light-DOM
 * {@code <slot>} bug ADR-0012 was written to kill: there is no slot, the body is owned markup).
 *
 * <p>Positioning stays the server-pure CSS path the partial documents (anchor-name on the trigger,
 * position-anchor + position-area + flip-block on the panel): zero {@code @floating-ui/dom}. The
 * panel still renders in normal flow anchored to the trigger; an adopter who needs the top-layer +
 * light-dismiss of the native popover can render the conditional panel with the {@code popover}
 * attribute and toggle it from {@link #render()} (documented seam, not the default).
 *
 * <p>Convention (blueprint 1.b): state is {@code @Wire public} fields; actions are
 * {@code @LievitAction} methods; the dialog-popover a11y (Radix Popover model) lives in the
 * template. {@code label} + {@code open} round-trip; {@code disabled} is locked so a client cannot
 * open a server-disabled popover by editing the snapshot.
 *
 * <p>Copied in by {@code lievit add popover-wire}: the adopter OWNS this class (rename it, move the
 * package, replace the toggle with a fetch-on-open, add server authz) AND the
 * {@code popover-wire.jte} template.
 */
@LievitComponent(template = "lievit/popover-wire")
public class PopoverComponent {

    /** Trigger label text. Client-editable, round-trips in the snapshot. */
    @Wire
    public String label = "";

    /** Open state: the single piece of disclosure state, held server-side so the panel content can
     * be (re)derived from server state on each open. */
    @Wire
    public boolean open = false;

    /**
     * Disables the trigger: blocks {@link #toggle()} / {@link #show()} and dims it. Locked so a
     * client cannot open a server-disabled popover by editing the snapshot payload.
     */
    @Wire
    @LievitProperty(locked = true)
    public boolean disabled = false;

    /**
     * Toggles the popover open/closed. A no-op while {@link #disabled}. On open, a real adopter
     * derives the panel content from server state here (fetch the filtered feed, build the form).
     */
    @LievitAction
    public void toggle() {
        if (disabled) {
            return;
        }
        open = !open;
    }

    /** Opens the popover (the trigger / a server flow). A no-op while {@link #disabled}. */
    @LievitAction
    public void show() {
        if (disabled) {
            return;
        }
        open = true;
    }

    /** Closes the popover (Escape / an outside click / a server flow). */
    @LievitAction
    public void close() {
        open = false;
    }
}

@import gg.jte.Content
@import gg.jte.output.StringOutput
@import gg.jte.html.escape.Escape
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui progress partial -- determinate / indeterminate progress in four visual forms.

  TIER: PARTIAL presentational -> JTE partial (ADR-0012 server-first pivot). Progress holds
  no client state: the fill width, SVG arc offset, and ARIA attributes are pure functions of
  the typed value + max, so the server renders them and the browser paints. The former island
  computed the same math client-side and streamed it back; that round-trip is not needed here.

  STRUCTURE (scientific decision rule):
    - WAI-ARIA APG Progressbar (WAI-ARIA 1.2 sec 5.3.22 + MDN ARIA progressbar_role):
      role="progressbar", aria-valuemin="0", aria-valuemax, aria-valuenow (OMITTED for
      indeterminate per spec), aria-valuetext. All inner children are presentational.
      The native <progress> element is preferred where custom styling is not required; for
      cross-browser token-driven theming a div+role pattern is standard (shadcn / Ant Design
      Progress reference). The native element's fill pseudo-elements vary by engine and cannot
      be reliably themed with --lv-* custom properties.
    - Inventory reference: Ant Design Progress (line / circle / dashboard / steps variants;
      striped + animated stripes; status intents; step segments). Feature-complete mapping to
      the lievit API surface.
    - Styling: ORIGINAL generation over --lv-* (OKLCH) tokens; visual look inspired by
      Tailwind UI (NO code copied).

  A11y (WAI-ARIA 1.2 progressbar role):
    - role="progressbar" on the root <div> -- always present.
    - aria-valuemin="0" -- always emitted (explicit for portability).
    - aria-valuemax="${max}" -- always emitted.
    - aria-valuenow -- emitted only when value != null (determinate); OMITTED for indeterminate:
      WAI-ARIA 1.2 specifies that the ABSENCE of aria-valuenow signals indeterminate to AT.
    - aria-valuetext="${valueText}" -- emitted only when valueText is non-null; overrides the
      AT percentage announcement (e.g. "15 of 30 files").
    - aria-labelledby -- takes precedence when non-null; aria-label used otherwise.
    - All inner children (SVG, segments, stripe overlay, showValue text) are aria-hidden="true":
      WAI-ARIA 1.2 states that all children of progressbar are treated as presentational.
    - The component is NOT focusable (no tabindex); no keyboard interaction; no focus trap.
    - NOT a live region: screen readers do not re-announce a progressbar on every valuenow
      change. For AT completion announcement, the consuming template owns a nearby role="status".
    - Accessible name MUST be provided (aria-label or aria-labelledby). When both are null the
      template emits a JTE comment so authors are not surprised; the component still renders.
    - No aria-busy on the progress bar itself: aria-busy belongs on the region being loaded.

  LIVE-REGION NOTE: progressbar is NOT in the WAI-ARIA live-region set (alert, log, marquee,
  status, timer). Periodic valuenow updates are NOT automatically announced. This is by design:
  continuous announcements would be disruptive for a file-upload counter. When the consumer
  needs AT to announce completion, the correct pattern is: set aria-busy="true" on the region
  being loaded (not on the progressbar), add aria-describedby on the region referencing the
  progressbar id, then set aria-busy="false" on completion and update a nearby role="status".

  STRIPED ANIMATION: requires `striped=true`; animated=true without striped=true is a no-op
  (a JTE comment nags). The animation CSS class references @keyframes lv-progress-stripe-move
  defined in lievit-tokens.css (CSP-clean, no inline style).

  Params:
    Integer value              = null      0..max determinate; null = indeterminate.
    int max                    = 100       aria-valuemax; minimum is always 0.
    String valueText           = null      aria-valuetext; overrides AT percentage announcement.
    String label               = null      aria-label (when labelledBy is null and label is set).
    String labelledBy          = null      aria-labelledby; takes precedence over label.
    String variant             = "default" INTENT: default | info | success | warning | destructive.
    String size                = "md"      sm | md | lg -- track height / stroke width.
    String form                = "line"    line | circle | dashboard | steps.
    boolean striped            = false     diagonal stripe pattern over the fill (line only).
    boolean animated           = false     animates the stripes; requires striped=true.
    boolean showValue          = false     renders a visible percentage label.
    int steps                  = 0         number of discrete segments (steps form only).
    int strokeWidth            = 0         SVG stroke override in px; 0 = size-driven default.
    String cssClass            = ""        extra utility classes on the root element.
    String attrs               = ""        TRUSTED raw ($unsafe) -- STATIC author-typed strings only.
    Map<String,String> dataAttrs = {}      SAFE escaped dynamic data-* (key w/o "data-"; each value
                                           via Escape.htmlAttribute).
    gg.jte.Content trailing    = null      slot after the bar (line form): status text, action.
    gg.jte.Content footer      = null      slot below the component (all forms): status text, note.

  ESCAPING (XSS decision rule):
    attrs     = TRUSTED raw ($unsafe) -- STATIC author-typed strings only (e.g. id="upload-progress").
                NEVER interpolate a per-row DB-derived value into attrs.
    dataAttrs = SAFE escaped Map<String,String>: each key validated as a simple identifier
                ([A-Za-z][A-Za-z0-9-]*), each value escaped via Escape.htmlAttribute.
    Per-row DB-derived values (e.g. a row id for a per-file upload) go through dataAttrs, never attrs.

  Usage:
    @@template.lievit.progress(value = 60, max = 100, label = "Uploading")
    @@template.lievit.progress(label = "Processing")
    @@template.lievit.progress(value = 75, form = "circle", size = "lg", showValue = true,
        variant = "success", label = "Sync complete")
    @@template.lievit.progress(value = 3, form = "steps", steps = 5, max = 5,
        label = "Step 3 of 5")
    @@template.lievit.progress(value = 40, striped = true, animated = true,
        variant = "info", label = "Uploading", labelledBy = "upload-heading")
--%>
@param Integer value = null
@param int max = 100
@param String valueText = null
@param String label = null
@param String labelledBy = null
@param String variant = "default"
@param String size = "md"
@param String form = "line"
@param boolean striped = false
@param boolean animated = false
@param boolean showValue = false
@param int steps = 0
@param int strokeWidth = 0
@param String cssClass = ""
@param String attrs = ""
@param java.util.Map<String, String> dataAttrs = java.util.Map.of()
@param gg.jte.Content trailing = null
@param gg.jte.Content footer = null

<%-- ---- state derivation ---- --%>
!{boolean _indeterminate = (value == null);}
!{boolean _complete = !_indeterminate && value != null && value >= max;}
!{String _state = _indeterminate ? "indeterminate" : (_complete ? "complete" : "determinate");}

<%-- ---- percentage (clamped 0..100) ---- --%>
!{double _pct = _indeterminate ? 0.0 : Math.min(100.0, Math.max(0.0, (value.doubleValue() / max) * 100.0));}
!{String _pctStr = String.format("%.4f", _pct) + "%";}

<%-- ---- aria-valuenow: null when indeterminate so JTE omits the attribute entirely ---- --%>
!{String _valuenow = _indeterminate ? null : String.valueOf(value);}

<%-- ---- accessible name resolution ---- --%>
!{String _ariaLabelledBy = (labelledBy != null && !labelledBy.isBlank()) ? labelledBy : null;}
!{String _ariaLabel = (_ariaLabelledBy == null && label != null && !label.isBlank()) ? label : null;}

<%-- ---- variant -> fill token ---- --%>
!{String _fillToken = switch (variant) {
    case "info"        -> "var(--lv-color-info)";
    case "success"     -> "var(--lv-color-success)";
    case "warning"     -> "var(--lv-color-warning)";
    case "destructive" -> "var(--lv-color-destructive)";
    default            -> "var(--lv-color-primary)";
  };}

<%-- ---- size -> track height token (line/steps) and stroke width (circle/dashboard) ---- --%>
!{String _heightToken = switch (size) {
    case "sm" -> "var(--lv-space-1)";
    case "lg" -> "var(--lv-space-3)";
    default   -> "var(--lv-space-2)";
  };}
!{int _strokePx = (strokeWidth > 0) ? strokeWidth : switch (size) {
    case "sm" -> 4;
    case "lg" -> 12;
    default   -> 8;
  };}

<%-- ---- fill class: indeterminate animation vs determinate stripe vs plain ---- --%>
!{boolean _doAnimate = animated && striped && !_indeterminate;}
!{String _fillClass = _indeterminate
    ? "lv-progress-fill lv-progress-fill--indeterminate animate-[lv-progress-slide_var(--lv-motion-duration-slow)_var(--lv-motion-easing-in-out)_infinite] motion-reduce:animate-none"
    : (striped
        ? (_doAnimate
            ? "lv-progress-fill lv-progress-fill--striped lv-progress-fill--animated animate-[lv-progress-stripe-move_1s_linear_infinite] motion-reduce:animate-none"
            : "lv-progress-fill lv-progress-fill--striped")
        : "lv-progress-fill");}

<%-- ---- showValue text for line / steps forms (rendered after the bar, aria-hidden) ---- --%>
!{String _showValueText = String.format("%.0f%%", _pct);}

<%-- ---- SVG arc math for circle / dashboard forms (server-side computation) ---- --%>
<%-- circle: full 360deg ring.  dashboard: 270deg arc from 135deg to 405deg (speedometer). --%>
<%-- Outer viewBox is 120x120; track circle + fill circle centred at (60,60) with r=54. --%>
!{int _svgSize = 120;}
!{int _cx = 60;}
!{int _cy = 60;}
!{int _r = 60 - (_strokePx / 2) - 2;}
!{double _circumference = 2.0 * Math.PI * _r;}

<%-- circle: offset = circumference * (1 - pct/100) so full clockwise from top ---- --%>
!{double _fillPct = _indeterminate ? 0.0 : _pct / 100.0;}
!{double _circleOffset = _circumference * (1.0 - _fillPct);}
!{String _circleOffsetStr = String.format("%.4f", _circleOffset);}
!{String _circumferenceStr = String.format("%.4f", _circumference);}

<%-- dashboard: 270deg arc. Starting angle = 135deg (bottom-left), sweep = 270deg.
     Rotation of the track + fill circles: -135deg so 0% starts at bottom-left.
     Offset for dashboard = circumference * (1 - fillPct) + (circumference * 0.25)
     because the track itself is only 270deg of the full circumference (25% is hidden). ---- --%>
!{double _dashCircumference = _circumference * 0.75;}
!{double _dashOffset = _circumference * (1.0 - _fillPct) + (_circumference * 0.25);}
!{String _dashOffsetStr = String.format("%.4f", _dashOffset);}

<%-- ---- SAFE dynamic data-* fragment (mirrors alert.jte exactly) ---- --%>
!{var _dataAttrs_ = new StringOutput();}
!{for (var e : dataAttrs.entrySet()) {
    if (e.getKey() != null && e.getKey().matches("[A-Za-z][A-Za-z0-9-]*")) {
      _dataAttrs_.writeContent(" data-" + e.getKey() + "=\"");
      Escape.htmlAttribute(e.getValue() == null ? "" : e.getValue(), _dataAttrs_);
      _dataAttrs_.writeContent("\"");
    }
  }}
!{var _dataAttrsMarkup = _dataAttrs_.toString();}

<%-- ---- accessible name nag (both null -> axe-core aria-progressbar-name fires) ---- --%>
@if(_ariaLabel == null && _ariaLabelledBy == null)
<%-- A11y nag: progress bar has no accessible name. Provide `label` or `labelledBy`. The axe-core
     aria-progressbar-name rule will flag this. The component renders anyway because the consuming
     template owns the labelling decision (e.g. a nearby visible heading may serve as the label). --%>
@endif

<%-- ======================================================================== --%>
<%-- ROOT: role=progressbar + full ARIA contract                              --%>
<%-- ======================================================================== --%>
<div
  data-slot="progress"
  data-variant="${variant}"
  data-size="${size}"
  data-state="${_state}"
  data-form="${form}"
  role="progressbar"
  aria-valuemin="0"
  aria-valuemax="${max}"
  aria-valuenow="${_valuenow}"
  aria-valuetext="${valueText}"
  aria-label="${_ariaLabel}"
  aria-labelledby="${_ariaLabelledBy}"
  $unsafe{_dataAttrsMarkup}
  class="${cssClass}"
  style="font-family:var(--lv-font-sans);"
  $unsafe{attrs}
>

  @if("circle".equals(form) || "dashboard".equals(form))
    <%-- ================================================================== --%>
    <%-- CIRCLE / DASHBOARD forms: inline SVG (aria-hidden, purely presentational) --%>
    <%-- ================================================================== --%>
    !{boolean _isDashboard = "dashboard".equals(form);}
    !{String _svgTransform = _isDashboard ? "rotate(135 60 60)" : "rotate(-90 60 60)";}
    !{double _visibleCircumference = _isDashboard ? _dashCircumference : _circumference;}
    !{String _fillOffset = _isDashboard ? _dashOffsetStr : _circleOffsetStr;}
    <div data-slot="progress-svg-wrap" class="relative inline-flex items-center justify-center" style="width:${_svgSize}px;height:${_svgSize}px;">
      <svg
        aria-hidden="true"
        viewBox="0 0 ${_svgSize} ${_svgSize}"
        fill="none"
        style="width:${_svgSize}px;height:${_svgSize}px;"
      >
        <%-- Track (unfilled rail) --%>
        <circle
          cx="${_cx}"
          cy="${_cy}"
          r="${_r}"
          stroke="var(--lv-color-muted-bg)"
          stroke-width="${_strokePx}"
          fill="none"
          transform="${_svgTransform}"
          stroke-dasharray="${_circumferenceStr} ${_circumferenceStr}"
          stroke-dashoffset="${_isDashboard ? String.format("%.4f", _circumference * 0.25) : "0"}"
          stroke-linecap="round"
        />
        <%-- Fill arc --%>
        @if(!_indeterminate)
          <circle
            data-slot="progress-fill"
            cx="${_cx}"
            cy="${_cy}"
            r="${_r}"
            stroke="${_fillToken}"
            stroke-width="${_strokePx}"
            fill="none"
            transform="${_svgTransform}"
            stroke-dasharray="${_circumferenceStr} ${_circumferenceStr}"
            stroke-dashoffset="${_fillOffset}"
            stroke-linecap="round"
            style="transition:stroke-dashoffset var(--lv-duration) var(--lv-ease);"
          />
        @else
          <%-- Indeterminate: a short arc that rotates (pure CSS animation on the wrapping div) --%>
          <circle
            data-slot="progress-fill"
            class="animate-[lv-progress-arc-spin_1.4s_var(--lv-motion-easing-in-out)_infinite] motion-reduce:animate-none"
            cx="${_cx}"
            cy="${_cy}"
            r="${_r}"
            stroke="${_fillToken}"
            stroke-width="${_strokePx}"
            fill="none"
            transform="${_svgTransform}"
            stroke-dasharray="${String.format("%.4f", _circumference * 0.25)} ${_circumferenceStr}"
            stroke-dashoffset="0"
            stroke-linecap="round"
          />
        @endif
        <%-- showValue: percentage text centred in the SVG (aria-hidden: already in aria-valuenow) --%>
        @if(showValue)
          <text
            aria-hidden="true"
            data-slot="progress-value-text"
            x="${_cx}"
            y="${_cy}"
            dominant-baseline="central"
            text-anchor="middle"
            style="font-family:var(--lv-font-sans);font-size:var(--lv-text-sm);font-weight:var(--lv-font-medium);fill:var(--lv-color-fg);"
          >${_showValueText}</text>
        @endif
      </svg>
    </div>
  @elseif("steps".equals(form) && steps > 0)
    <%-- ================================================================== --%>
    <%-- STEPS form: discrete filled/empty segment spans                    --%>
    <%-- ================================================================== --%>
    !{int _filledCount = _indeterminate ? 0 : (int) Math.round((_pct / 100.0) * steps);}
    <div
      data-slot="progress-steps"
      class="flex w-full gap-[var(--lv-space-1)]"
    >
      @for(int _si = 0; _si < steps; _si++)
        <span
          aria-hidden="true"
          data-slot="${_si < _filledCount ? "progress-step-filled" : "progress-step-empty"}"
          class="flex-1 rounded-[var(--lv-radius-full)] transition-colors"
          style="height:${_heightToken};background:${_si < _filledCount ? _fillToken : "var(--lv-color-muted-bg)"};"
        ></span>
      @endfor
    </div>
    @if(showValue)
      <span
        aria-hidden="true"
        data-slot="progress-value-text"
        class="ml-[var(--lv-space-2)] shrink-0 tabular-nums"
        style="font-size:var(--lv-text-sm);color:var(--lv-color-fg);font-family:var(--lv-font-sans);"
      >${_showValueText}</span>
    @endif
    @if(trailing != null)
      <div data-slot="progress-trailing" class="mt-[var(--lv-space-1)]">${trailing}</div>
    @endif
  @else
    <%-- ================================================================== --%>
    <%-- LINE form (default): horizontal bar track + fill                   --%>
    <%-- ================================================================== --%>
    <div class="flex w-full items-center gap-[var(--lv-space-2)]">
      <div
        data-slot="progress-track"
        class="relative flex-1 overflow-hidden rounded-[var(--lv-radius-full)]"
        style="height:${_heightToken};background:var(--lv-color-muted-bg);"
      >
        @if(_indeterminate)
          <div
            data-slot="progress-fill"
            aria-hidden="true"
            class="${_fillClass} absolute inset-y-0 left-0 rounded-[var(--lv-radius-full)]"
            style="width:40%;background:${_fillToken};"
          ></div>
        @else
          <div
            data-slot="progress-fill"
            aria-hidden="true"
            class="${_fillClass} absolute inset-y-0 left-0 rounded-[var(--lv-radius-full)] transition-[width]"
            style="width:${_pctStr};background:${_fillToken};${striped ? "background-image:repeating-linear-gradient(-45deg,color-mix(in oklch,"+_fillToken+" 70%,transparent) 0,color-mix(in oklch,"+_fillToken+" 70%,transparent) 6px,transparent 6px,transparent 12px);" : ""}"
          ></div>
        @endif
      </div>
      @if(showValue)
        <span
          aria-hidden="true"
          data-slot="progress-value-text"
          class="shrink-0 tabular-nums"
          style="font-size:${size.equals("sm") ? "var(--lv-text-xs)" : "var(--lv-text-sm)"};color:var(--lv-color-fg);font-family:var(--lv-font-sans);"
        >${_showValueText}</span>
      @endif
    </div>
    @if(trailing != null)
      <div data-slot="progress-trailing" class="mt-[var(--lv-space-1)]">${trailing}</div>
    @endif
  @endif

  <%-- ---- footer slot (all forms) ---- --%>
  @if(footer != null)
    <div data-slot="progress-footer" class="mt-[var(--lv-space-2)]">${footer}</div>
  @endif
</div>

@import gg.jte.output.StringOutput
@import gg.jte.html.escape.Escape
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui radio-group partial -- a mutually-exclusive option group (APG Radio Group).

  TIER: PARTIAL presentational -> JTE partial (ADR-0012 server-first pivot). PARTIAL because the
  selected value is a server fact: the controller reads it from the domain model and passes it as
  `value`; the partial renders aria-checked and tabindex from that server-provided selection.

  Options arrive via FOUR parallel lists (`optionIds`, `optionLabels`, `optionDescriptions`,
  `optionDisabled`) -- the same parallel-list pattern used by command.jte, data-table.jte,
  and other partials. The controller zips the domain List<RadioOption> into these four
  before calling the template; no domain type needs to be on the JTE compile classpath.

  The one irreducible client behaviour for the custom variants is roving-tabindex arrow-key
  navigation (APG Radio Group) -- this is the radio-group.enhancer.ts escape-hatch.
  The native variant (`nativeInputs=true`) needs no enhancer: the platform provides identical
  roving and arrow-key behaviour for real radio inputs sharing a `name`.

  STRUCTURE (scientific decision rule):
  a11y source: WAI-ARIA APG Radio Group (https://www.w3.org/WAI/ARIA/apg/patterns/radio/).
  Example verified: https://www.w3.org/WAI/ARIA/apg/patterns/radio/examples/radio/.
  react-aria `useRadioGroup` / `useRadio` consulted as interaction pattern reference (ORIGINAL
  output, no code copied -- 02-licensing.md).
  Inventory reference: Ant Design Radio (sizes, button-style group, vertical/horizontal layout,
  disabled per-option, disabled whole group).
  Styling: ORIGINAL token-driven generation; look inspired by Tailwind UI (no code copied).

  Two rendering paths:

  PATH A -- custom variant (default + button + button-vertical):
    Root: `div role="radiogroup"` carrying `aria-labelledby`, `data-lievit-enhancer="radio-group"`.
    Options: `div role="radio"` with `aria-checked`, `aria-disabled`, roving `tabindex`.
    Enhancer: radio-group.enhancer.ts mounts on `data-lievit-enhancer="radio-group"` and drives
    arrow-key navigation + aria-checked sync + lievit:radio-change dispatch.
    The custom indicator (ring + dot) is `data-slot="radio-indicator"`, button variants omit it.

  PATH B -- native variant (`nativeInputs=true`):
    Root: `fieldset` + `legend`. Each option: `input type="radio"` + `label for`. The shared `name`
    enforces single-select; the platform supplies roving arrow-key focus. No enhancer.

  A11y (WAI-ARIA APG Radio Group):
    Roles: role="radiogroup" (custom), fieldset+legend (native), role="radio" / input[type=radio].
    States: aria-checked="true|false", aria-disabled, aria-required, aria-invalid (from field).
    Keyboard (custom path, enhancer-driven): ArrowDown/Right -> next (wrap, skip disabled) + check;
    ArrowUp/Left -> prev + check; Space -> check focused if unchecked; Enter -> no-op (APG).
    Focus: roving tabindex -- exactly one option holds tabindex="0" (checked one, or first
    non-disabled if none checked). Tab exits the group normally (no trap).
    Live region: none -- screen readers announce label + aria-checked on focus movement.

  Escaping channels (the XSS decision rule, verbatim from button.jte):
    attrs       = TRUSTED raw ($unsafe) -- STATIC, author-typed strings ONLY (l:change, data-testid).
                  NEVER interpolate per-row or DB-derived values into attrs.
    dataAttrs   = SAFE escaped Map of String to String: each value through Escape.htmlAttribute.
    optionAttrs = SAFE escaped Map of String to String propagated to each option element.
    data-value  = always escaped via Escape.htmlAttribute (option id is potentially DB-derived).

  Params:
    String name                         REQUIRED. HTML `name` shared by all options.
    List<String> optionIds              REQUIRED. Submitted values, one per option.
    List<String> optionLabels           REQUIRED. Visible text, parallel to optionIds.
    List<String> optionDescriptions     Optional hint per option (null entry = no description).
                                        Parallel to optionIds; null or shorter list = no descriptions.
    List<Boolean> optionDisabled        Optional per-option disabled flags. Parallel to optionIds;
                                        null or shorter list = all enabled.
    String value = null                 Currently selected option id. null = nothing selected.
    String variant = "default"          "default" | "button" | "button-vertical"
    String size = "md"                  "sm" | "md" | "lg" -- height-based, toolbar-aligned.
    String layout = "vertical"          "vertical" | "horizontal" -- default variant only.
    boolean disabled = false            Disables the entire group.
    boolean required = false            aria-required="true" on the radiogroup.
    String labelledby = null            id of an external label element (aria-labelledby).
    String groupLabel = null            Inline group label text rendered inside the partial.
    String groupLabelId = null          id on the inline label element (auto: "rg-label-" + name).
    String describedby = null           id(s) of external hint/error elements (aria-describedby).
    boolean nativeInputs = false        Render real input[type=radio] with fieldset/legend.
    String cssClass = ""                Extra utility classes on the root element.
    String optionCssClass = ""          Extra utility classes on each option wrapper.
    String attrs = ""                   TRUSTED raw ($unsafe) -- STATIC strings only.
    Map<String,String> dataAttrs = {}   SAFE dynamic data-* (value escaped via Escape.htmlAttribute).
    Map<String,String> optionAttrs = {} SAFE per-option data-* (value escaped).

  Usage:
    @@template.lievit.radio_group(
      name = "priority",
      optionIds = priorityIds,
      optionLabels = priorityLabels,
      value = form.priority(),
      groupLabel = "Priorita",
      attrs = "l:change=\"updatePriority\""
    )
    @@template.lievit.radio_group(
      name = "role",
      optionIds = roleIds,
      optionLabels = roleLabels,
      value = form.role(),
      variant = "button",
      size = "sm",
      groupLabel = "Ruolo",
      nativeInputs = false
    )
--%>
@param String name
@param java.util.List<String> optionIds
@param java.util.List<String> optionLabels
@param java.util.List<String> optionDescriptions = null
@param java.util.List<Boolean> optionDisabled = null
@param String value = null
@param String variant = "default"
@param String size = "md"
@param String layout = "vertical"
@param boolean disabled = false
@param boolean required = false
@param String labelledby = null
@param String groupLabel = null
@param String groupLabelId = null
@param String describedby = null
@param boolean nativeInputs = false
@param String cssClass = ""
@param String optionCssClass = ""
@param String attrs = ""
@param java.util.Map<String, String> dataAttrs = java.util.Map.of()
@param java.util.Map<String, String> optionAttrs = java.util.Map.of()

<%-- Resolve the effective group-label id: use the provided one or auto-derive from name. --%>
!{var effectiveLabelId = (groupLabelId != null && !groupLabelId.isBlank())
    ? groupLabelId
    : "rg-label-" + name;}

<%-- Resolve aria-labelledby: inline groupLabel wins if set; fall back to external labelledby. --%>
!{var rootLabelledBy = (groupLabel != null && !groupLabel.isBlank()) ? effectiveLabelId : labelledby;}
<%-- If both are set, composite them (space-separated). --%>
!{var compositeLabelledBy = (groupLabel != null && !groupLabel.isBlank()
    && labelledby != null && !labelledby.isBlank())
    ? effectiveLabelId + " " + labelledby
    : rootLabelledBy;}

<%-- Option touch-target height class (toolbar-aligned per architecture contract S5.b):
     sm -> --lv-space-8 (32px), md -> --lv-space-9 (36px), lg -> --lv-space-10 (40px). --%>
!{var minHeightClass = switch (size) {
    case "sm" -> "min-h-[var(--lv-space-8)]";
    case "lg" -> "min-h-[var(--lv-space-10)]";
    default   -> "min-h-[var(--lv-space-9)]";
  };}

<%-- Text-size class per size step. --%>
!{var textSizeClass = switch (size) {
    case "sm" -> "text-[length:var(--lv-text-xs)]";
    case "lg" -> "text-[length:var(--lv-text-base)]";
    default   -> "text-[length:var(--lv-text-sm)]";
  };}

<%-- Button-variant pill height (flush with same-size button/input). --%>
!{var btnHeightClass = switch (size) {
    case "sm" -> "h-[var(--lv-space-8)]";
    case "lg" -> "h-[var(--lv-space-10)]";
    default   -> "h-[var(--lv-space-9)]";
  };}

<%-- Layout flex direction for the default variant. --%>
!{var layoutClass = "horizontal".equals(layout) ? "flex-row flex-wrap" : "flex-col";}

<%-- SAFE dynamic data-* fragment builder (pattern from badge.jte / switch.jte). --%>
!{var dataAttrs_ = new StringOutput();}
!{for (var e : dataAttrs.entrySet()) {
    if (e.getKey() != null && e.getKey().matches("[A-Za-z][A-Za-z0-9-]*")) {
      dataAttrs_.writeContent(" data-" + e.getKey() + "=\"");
      Escape.htmlAttribute(e.getValue() == null ? "" : e.getValue(), dataAttrs_);
      dataAttrs_.writeContent("\"");
    }
  }}
!{var dataAttrsMarkup = dataAttrs_.toString();}

<%-- Per-option data-* fragment (optionAttrs applied to every option element). --%>
!{var optionAttrs_ = new StringOutput();}
!{for (var e : optionAttrs.entrySet()) {
    if (e.getKey() != null && e.getKey().matches("[A-Za-z][A-Za-z0-9-]*")) {
      optionAttrs_.writeContent(" data-" + e.getKey() + "=\"");
      Escape.htmlAttribute(e.getValue() == null ? "" : e.getValue(), optionAttrs_);
      optionAttrs_.writeContent("\"");
    }
  }}
!{var optionAttrsMarkup = optionAttrs_.toString();}

@if(!nativeInputs)
<%-- =========================================================================
     PATH A: custom variant (default | button | button-vertical)
     role="radiogroup" + role="radio" divs + radio-group.enhancer.ts
     ========================================================================= --%>

<%-- Find the first non-disabled option id for tabindex when nothing is checked. --%>
!{String firstEnabledId = null;}
!{for (int _fi = 0; _fi < optionIds.size(); _fi++) {
    if (firstEnabledId == null) {
      boolean _fd = disabled || (optionDisabled != null && _fi < optionDisabled.size() && Boolean.TRUE.equals(optionDisabled.get(_fi)));
      if (!_fd) { firstEnabledId = optionIds.get(_fi); }
    }
  }}
<%-- Fallback: all options disabled -> first option still gets tabindex=0 (structural reachability). --%>
!{if (firstEnabledId == null && !optionIds.isEmpty()) { firstEnabledId = optionIds.get(0); }}

<div
  role="radiogroup"
  id="rg-${name}"
  aria-labelledby="${compositeLabelledBy}"
  aria-describedby="${describedby}"
  aria-required="${required ? "true" : null}"
  aria-disabled="${disabled ? "true" : null}"
  data-slot="radio-group"
  data-variant="${variant}"
  data-size="${size}"
  data-layout="${layout}"
  data-lievit-enhancer="radio-group"
  class="${cssClass}"
  style="font-family:var(--lv-font-sans);"
  $unsafe{dataAttrsMarkup}
  $unsafe{attrs}
>
  @if(groupLabel != null && !groupLabel.isBlank())
    <%-- Inline group label: referenced by aria-labelledby; aria-hidden because the radiogroup
         aria-labelledby already announces it to AT. --%>
    <span
      id="${effectiveLabelId}"
      data-slot="radio-group-label"
      aria-hidden="true"
      class="${textSizeClass} font-[var(--lv-font-medium)] text-[var(--lv-color-fg)] mb-[var(--lv-space-2)] block"
    >${groupLabel}</span>
  @endif

  @if("button".equals(variant) || "button-vertical".equals(variant))
    <%-- BUTTON / BUTTON-VERTICAL variant: segmented button-bar, no indicator dots. --%>
    <div
      data-slot="radio-group-options"
      class="${"button-vertical".equals(variant) ? "flex flex-col" : "inline-flex flex-row"} rounded-[var(--lv-radius-md)] border border-[var(--lv-color-border)] overflow-hidden"
    >
      @for(int _i = 0; _i < optionIds.size(); _i++)
        !{var _id = optionIds.get(_i);}
        !{var _label = (_i < optionLabels.size()) ? optionLabels.get(_i) : "";}
        !{boolean _checked = _id != null && _id.equals(value);}
        !{boolean _optDis = disabled || (optionDisabled != null && _i < optionDisabled.size() && Boolean.TRUE.equals(optionDisabled.get(_i)));}
        !{boolean _isTabStop = _checked || (!_checked && _id != null && _id.equals(firstEnabledId) && (value == null || optionIds.stream().noneMatch(oid -> oid != null && oid.equals(value))));}
        !{var _esc = new StringOutput();}
        !{Escape.htmlAttribute(_id == null ? "" : _id, _esc);}
        !{var _escId = _esc.toString();}
        <div
          role="radio"
          id="rg-${name}-${_escId}"
          aria-checked="${_checked ? "true" : "false"}"
          aria-disabled="${_optDis ? "true" : "false"}"
          tabindex="${_isTabStop ? "0" : "-1"}"
          data-slot="radio-option"
          data-value="${_escId}"
          class="${btnHeightClass} ${textSizeClass} flex items-center justify-center px-[var(--lv-space-3)] font-[var(--lv-font-medium)] cursor-pointer select-none transition-colors border-r border-[var(--lv-color-border)] last:border-r-0 outline-none focus-visible:shadow-[var(--lv-ring)] focus-visible:relative focus-visible:z-10 aria-checked:bg-[var(--lv-color-primary)] aria-checked:text-[var(--lv-color-primary-fg)] aria-[checked=false]:bg-[var(--lv-color-input)] aria-[checked=false]:text-[var(--lv-color-fg)] aria-[checked=false]:hover:bg-[var(--lv-color-accent)] aria-[checked=false]:hover:text-[var(--lv-color-accent-fg)] aria-disabled:cursor-not-allowed aria-disabled:opacity-[var(--lv-opacity-disabled)] ${optionCssClass}"
          $unsafe{optionAttrsMarkup}
        >${_label}</div>
      @endfor
    </div>

  @else
    <%-- DEFAULT variant: stacked or horizontal radio pills with custom indicator dot. --%>
    <div
