                !{var isSelected = _instance.isChosen(opt.value());}
                !{var selectable = !opt.disabled() && !disabled;}
                !{var pickAction = multiple ? "$set('toggleValue', '" + opt.value() + "')" : "$set('selected', '" + opt.value() + "')";}
